#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define PIR_PIN_1 17
#define PIR_PIN_2 22
#define BUZZER_PIN 18

// Log file name
#define LOG_FILE "motion_log.txt"

// Buzzer duration (milliseconds)
#define BUZZER_DURATION 500

volatile sig_atomic_t program_running = 1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    fprintf(stderr, "\nCaught signal, exiting gracefully...\n");
}

// Function to get current timestamp as a string
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    static char timestamp[20]; // Ensure it's static to persist after function returns

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Function to log motion event to file
void log_motion(int pin) {
    FILE *fp;
    char *timestamp = get_timestamp();

    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    fprintf(fp, "%s: Motion detected on pin %d\n", timestamp, pin);
    fclose(fp);
    printf("%s: Motion detected on pin %d\n", timestamp, pin);
}

// Function to activate the buzzer
void activate_buzzer() {
    gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
    gpioDelay(BUZZER_DURATION * 1000); // Delay for specified duration (microseconds)
    gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
}

// Callback function for PIR sensor 1
void pir_callback_1(int gpio, int level, uint32_t tick) {
    if (level == PI_HIGH) { // Rising edge (motion detected)
        log_motion(gpio);
        activate_buzzer();
    }
}

// Callback function for PIR sensor 2
void pir_callback_2(int gpio, int level, uint32_t tick) {
    if (level == PI_HIGH) { // Rising edge (motion detected)
        log_motion(gpio);
        activate_buzzer();
    }
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure PIR sensor pins as inputs with pull-down resistors
    if (gpioSetMode(PIR_PIN_1, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set mode for PIR_PIN_1\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetPullUpDown(PIR_PIN_1, PI_PUD_DOWN) != 0) {
        fprintf(stderr, "Failed to set pull-up/down for PIR_PIN_1\n");
        gpioTerminate();
        return 1;
    }

    if (gpioSetMode(PIR_PIN_2, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set mode for PIR_PIN_2\n");
        gpioTerminate();
        return 1;
    }
    if (gpioSetPullUpDown(PIR_PIN_2, PI_PUD_DOWN) != 0) {
        fprintf(stderr, "Failed to set pull-up/down for PIR_PIN_2\n");
        gpioTerminate();
        return 1;
    }

    // Configure buzzer pin as output
    if (gpioSetMode(BUZZER_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set mode for BUZZER_PIN\n");
        gpioTerminate();
        return 1;
    }

    // Set initial state of buzzer to off
    gpioWrite(BUZZER_PIN, 0);

    // Set up interrupt routines for PIR sensors
    if (gpioSetISRFunc(PIR_PIN_1, RISING_EDGE, 0, pir_callback_1) != 0) {
        fprintf(stderr, "Failed to set ISR for PIR_PIN_1\n");
        gpioTerminate();
        return 1;
    }

    if (gpioSetISRFunc(PIR_PIN_2, RISING_EDGE, 0, pir_callback_2) != 0) {
        fprintf(stderr, "Failed to set ISR for PIR_PIN_2\n");
        gpioTerminate();
        return 1;
    }

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Keep the program running until a signal is received
    while (program_running) {
        gpioDelay(100); // Check every 100ms
    }

    // Clean up and terminate pigpio
    gpioTerminate();
    return 0;
}

