#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>

int main(int argc, char *argv[])
{
	// Variables
	int gpio_pir = 17; // GPIO Pin 17 (interrupt)
	int gpio_buzzer = 18; // GPIO Pin 18 (interrupt)

	// pigpio initialization
	if (pigpio_start(NULL, NULL) < 0) {
		printf("Error initializing pigpio\n");
		return EXIT_FAILURE;
	}

	// Setup for GPIO pin 17 (PIR)
	if (gpioSetMode(gpio_pir, PI_INPUT) < 0) {
		printf("Error setting mode on GPIO pin 17\n");
		return EXIT_FAILURE;
	}

	// Setup for GPIO pin 18 (Buzzer)
	if (gpioSetMode(gpio_buzzer, PI_OUTPUT) < 0) {
		printf("Error setting mode on GPIO pin 18\n");
		return EXIT_FAILURE;
	}

	// Setup interrupt GPIO 17
	if (gpioSetISRFunc(gpio_pir, PI_EITHER_EDGE, gpio_isr_pir) < 0) {
		printf("Error setting interrupt on GPIO pin 17\n");
		return EXIT_FAILURE;
	}

	// Infinite loop
	while(1) {
		printf("Ready\n");
		sleep(10);
	}

	// Error handling
	if (pigpio_stop() < 0) {
		printf("Error ending pigpio\n");
		return EXIT_FAILURE;
	}

	return EXIT_SUCCESS;
}

// Interrupt function for GPIO 17
int gpio_isr_pir(int gpio, int level, uint32_t tick)
{
	printf("PIR triggered\n");
	gpioWrite(gpio_buzzer, PI_ON);
	sleep(1);
	gpioWrite(gpio_buzzer, PI_OFF);
	return 0;
}
