    gpioDelay(duration_ms * 1000); // Delay for specified duration (microseconds)
    gpioWrite(BUZZER_PIN, 0); // Turn off buzzer
}

// Interrupt handler for PIR sensor
void pir_interrupt_handler(int gpio, int level, unsigned int tick, void *user)
{
    unsigned int current_time = tick;

    // Debouncing: check if enough time has passed since the last interrupt
    if (current_time - last_interrupt_time > DEBOUNCE_TIME * 1000) // Convert ms to microseconds
    {
        printf("Motion detected!\n");
        activate_buzzer(500); // Activate buzzer for 500ms
        last_interrupt_time = current_time;
    }
}

int main()
{
    // Initialize pigpio library
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure PIR sensor pin as input with pull-down resistor
    if (gpioSetMode(PIR_PIN, PI_INPUT) != 0)
    {
        fprintf(stderr, "Failed to set PIR pin as input\n");
        gpioTerminate();
        return 1;
    }
    gpioSetPullUpDown(PIR_PIN, PI_PUD_DOWN);

