    if (gpioSetMode(BUZZER_PIN, PI_OUTPUT) != 0)
    {
        fprintf(stderr, "Failed to set Buzzer pin as output\n");
        gpioTerminate();
        return 1;
    }

    // Set initial state of buzzer to off
    gpioWrite(BUZZER_PIN, 0);

    // Register interrupt handler for PIR sensor
    if (gpioSetAlertFuncEx(PIR_PIN, pir_interrupt_handler, NULL) != 0)
    {
        fprintf(stderr, "Failed to set interrupt handler for PIR sensor\n");
        gpioTerminate();
        return 1;
    }

    // Set up signal handlers for clean shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

