#define ALARM_FREQ_LOW 1000
#define ALARM_FREQ_HIGH 1500
#define DISTANCE_LOW 20
#define DISTANCE_HIGH 10

volatile sig_atomic_t program_running = 1;

void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C detected. Exiting gracefully.\n");
        program_running = 0;
    }
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(BUZZER1_PIN, PI_OUTPUT);
    gpioSetMode(BUZZER2_PIN, PI_OUTPUT);

    signal(SIGINT, signal_handler);

    int distance;
    while (program_running) {
        if (scanf("%d", &distance) == 1) {
            if (distance >= 0 && distance <= 100) {
                if (distance < DISTANCE_LOW) {
                    gpioPWM(BUZZER1_PIN, 255);
                    gpioPWM(BUZZER2_PIN, 128);
                    gpioSetPWMfrequency(BUZZER1_PIN, ALARM_FREQ_LOW);
                    gpioSetPWMfrequency(BUZZER2_PIN, ALARM_FREQ_HIGH);
                } else if (distance < DISTANCE_HIGH) {
                    gpioPWM(BUZZER1_PIN, 128);
                    gpioPWM(BUZZER2_PIN, 255);
                    gpioSetPWMfrequency(BUZZER1_PIN, ALARM_FREQ_HIGH);
                    gpioSetPWMfrequency(BUZZER2_PIN, ALARM_FREQ_LOW);
                } else {
                    gpioPWM(BUZZER1_PIN, 0);
                    gpioPWM(BUZZER2_PIN, 0);
                }
            } else {
                fprintf(stderr, "Invalid distance value. Please enter a number between 0 and 100.\n");
            }
        } else {
            fprintf(stderr, "Invalid input. Please enter a number.\n");
            while (getchar() != '\n'); // Clear input buffer
        }
    }

    gpioPWM(BUZZER1_PIN, 0);
    gpioPWM(BUZZER2_PIN, 0);
    gpioTerminate();
    return 0;
}
