void check_pin(int pin)
{
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        exit(EXIT_FAILURE);
    }

    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        exit(EXIT_FAILURE);
    }

    if (wiringPiISR(pin, INT_EDGE_BOTH, &motion_detected) == -1) {
        fprintf(stderr, "wiringPiISR failed: %s\n", strerror(errno));
        exit(EXIT_FAILURE);
    }
}

void motion_detected(void)
{
    time_t now;
    struct tm *timeinfo;
    char buffer[80];

    now = time(NULL);
    timeinfo = localtime(&now);

    strftime(buffer, sizeof(buffer), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (wiringPiISR(17, INT_EDGE_BOTH, &motion_detected) == -1) {
        fprintf(stderr, "wiringPiISR failed: %s\n", strerror(errno));
        exit(EXIT_FAILURE);
    }

    FILE *fp = fopen("motion.log", "a");

    if (fp == NULL) {
        fprintf(stderr, "fopen failed: %s\n", strerror(errno));
        exit(EXIT_FAILURE);
    }

    fprintf(fp, "%s\n", buffer);
    fclose(fp);
}

int main()
{
    check_pin(17);

    return 0;
}
