volatile sig_atomic_t program_running = 1;
FILE *log_file = NULL;

void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
}

int initialize_gpio() {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi. Please check permissions and wiring.\n");
        return 1;
    }

    pinMode(MOTION_SENSOR_PIN, INPUT);
    pullUpDnControl(MOTION_SENSOR_PIN, PUD_DOWN); // Use a pull-down resistor
    return 0;
}

int read_motion_sensor() {
    return digitalRead(MOTION_SENSOR_PIN);
}

int log_motion_event(int motion_detected) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file == NULL) {
        log_file = fopen(LOG_FILE, "a");
        if (log_file == NULL) {
            fprintf(stderr, "Error opening log file!\n");
            return 1;
        }
    }

    fprintf(log_file, "%s: Motion %s\n", timestamp, motion_detected ? "Detected" : "Not Detected");
    fflush(log_file); // Ensure immediate write to file
    return 0;
}

int main() {
    signal(SIGINT, signal_handler);

    if (initialize_gpio() != 0) {
        return 1;
    }

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    while (program_running) {
        int motion_detected = read_motion_sensor();
        if (motion_detected == HIGH) {
            log_motion_event(1);
        } else if (motion_detected == LOW) {
            log_motion_event(0);
        }
        delay(100); // Debounce
    }

    if (log_file != NULL) {
