# Motion Detection with OpenCV and Raspberry Pi

### Instruction:
Write a C program for Raspberry Pi 5 using the OpenCV library to detect motion via a PIR sensor connected to GPIO 17 and log timestamped frame numbers to a "motion_log.txt" file, handling potential `opencv_frame` failures.

### Response:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <wiringPi.h>
#include <opencv2/opencv.hpp>
#include <errno.h>

#define PIR_PIN 17
#define LOG_FILE "motion_log.txt"
#define SERVER_IP "192.168.1.100"
#define SERVER_PORT 5000

static volatile int keepRunning = 1;

void intHandler(int dummy) {
    keepRunning = 0;
}

class MotionDetector {
private:
    int socket_desc;
    FILE *logFile;
    int frameNumber;

public:
    MotionDetector() {
        frameNumber = 0;
        if (wiringPiSetupGpio() == -1) {
            fprintf(stderr, "wiringPiSetupGpio failed, exiting...\n");
            exit(1);
        }
        pinMode(PIR_PIN, INPUT);
        pullUpDnControl(PIR_PIN, PUD_DOWN);
        socket_desc = 0;
        logFile = NULL;
    }

    ~MotionDetector() {
        if (logFile != NULL) {
            fclose(logFile);
        }
        if (socket_desc > 0) {
            close(socket_desc);
        }
    }

    void detectMotion() {
        if (digitalRead(PIR_PIN) == HIGH) {
            frameNumber++;

            time_t rawtime;
            struct tm *timeinfo;
            char timestamp[20];

            time(&rawtime);
            timeinfo = localtime(&rawtime);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            logFile = fopen(LOG_FILE, "a");
            if (logFile == NULL) {
                perror("Error opening log file");
                return;
            }

            fprintf(logFile, "%s - Frame: %d\n", timestamp, frameNumber);
            fclose(logFile);

            char server_ip[20];
            strcpy(server_ip, SERVER_IP);

            struct sockaddr_in server;
            server.sin_family = AF_INET;
            server.sin_port = htons(SERVER_PORT);
            server.sin_addr.s_addr = inet_addr(server_ip);

            socket_desc = socket(AF_INET, SOCK_STREAM, 0);
            if (socket_desc == -1) {
                perror("Could not create socket");
                return;
            }

            if (connect(socket_desc, (struct sockaddr *)&server, sizeof(server)) < 0) {
                perror("Connect error");
                close(socket_desc);
                socket_desc = 0;
                return;
            }

            char message[100];
            sprintf(message, "%s - Frame: %d", timestamp, frameNumber);
            if (send(socket_desc, message, strlen(message), 0) < 0) {
                perror("Send failed");
                close(socket_desc);
                socket_desc = 0;
            }
            close(socket_desc);
            socket_desc = 0;
        }
    }
};

int main() {
    MotionDetector motionDetector;
    signal(SIGINT, intHandler);

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    while (keepRunning) {
        motionDetector.detectMotion();
        delay(100);
    }

    printf("Exiting gracefully...\n");
    return 0;
}

