#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define PIR_PIN 4
#define BUZZER_PIN 18

// Log file name
#define LOG_FILE "motion_log.txt"

// Buzzer activation duration (milliseconds)
#define BUZZER_DURATION 1000

// Global variable for log file pointer
FILE *log_file = NULL;

// Function prototypes
void motion_detected(int gpio, int level, uint32_t tick, void *user_data);
void activate_buzzer(int duration_ms);
void log_motion_event(uint32_t timestamp);
void signal_handler(int signal);

// Function to activate the buzzer
void activate_buzzer(int duration_ms) {
    gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
    gpioDelay(duration_ms * 1000); // Delay for specified duration (microseconds)
    gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
}

// Function to log motion events
void log_motion_event(uint32_t timestamp) {
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    struct tm *timeinfo;
    char timestamp_str[30];

    timeinfo = localtime(&ts.tv_sec);
    strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s,%ld\n", timestamp_str, timestamp);
    fflush(log_file); // Ensure data is written to file immediately
}

// Interrupt handler function
void motion_detected(int gpio, int level, uint32_t tick, void *user_data) {
    (void)user_data; // Suppress unused parameter warning
    (void)gpio; // Suppress unused parameter warning
    (void)level; // Suppress unused parameter warning

    uint32_t timestamp = tick;

    activate_buzzer(BUZZER_DURATION);
    log_motion_event(timestamp);
}

// Signal handler for clean exit
void signal_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    gpioWrite(BUZZER_PIN, 0); // Ensure buzzer is off
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure PIR sensor pin as input
    gpioSetMode(PIR_PIN, PI_INPUT);

    // Configure buzzer pin as output
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    // Set up interrupt handler for motion detection
    if (gpioSetISRFuncEx(PIR_PIN, RISING_EDGE, 0, motion_detected, NULL) != 0) {
        fprintf(stderr, "Error setting up interrupt handler!\n");
        fclose(log_file);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Main loop (keep the program running)
    while (1) {
        gpioDelay(100000); // Check every 0.1 seconds
    }

    return 0; // This line will never be reached due to the infinite loop
}
