#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <string.h>
#include <unistd.h>

#define PIR_GPIO 23
#define BUZZER_GPIO 18

// Structure representing the PIR sensor
typedef struct {
    int gpio;
} PIRSensor;

// Structure representing the Buzzer
typedef struct {
    int gpio;
} Buzzer;

// Initializes a PIRSensor
PIRSensor* PIRSensor_init(int gpio) {
    PIRSensor* sensor = (PIRSensor*)malloc(sizeof(PIRSensor));
    if (sensor == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return NULL;
    }
    sensor->gpio = gpio;
    gpioSetMode(gpio, PI_INPUT); // Set GPIO as input
    gpioSetPullUpDown(gpio, PI_PUD_DOWN); // Enable pull-down resistor
    return sensor;
}

// Reads the current state of the PIR sensor
int PIRSensor_readSensor(PIRSensor* sensor) {
    return gpioRead(sensor->gpio);
}

// Initializes a Buzzer
Buzzer* Buzzer_init(int gpio) {
    Buzzer* buzzer = (Buzzer*)malloc(sizeof(Buzzer));
    if (buzzer == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return NULL;
    }
    buzzer->gpio = gpio;
    gpioSetMode(gpio, PI_OUTPUT); // Set GPIO as output
    return buzzer;
}

// Activates the buzzer
void Buzzer_activate(Buzzer* buzzer) {
    gpioWrite(buzzer->gpio, 1); // Set GPIO to high (activate buzzer)
}

// Deactivates the buzzer
void Buzzer_deactivate(Buzzer* buzzer) {
    gpioWrite(buzzer->gpio, 0); // Set GPIO to low (deactivate buzzer)
}

// Function to get the current timestamp in YYYY-MM-DD HH:MM:SS format
void getTimestamp(char* timestamp) {
    time_t rawtime;
    struct tm* timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Exit with an error code
    }

    // Instantiate the PIR sensor and Buzzer
    PIRSensor* pir = PIRSensor_init(PIR_GPIO);
    if (pir == NULL) {
        gpioTerminate();
        return 1;
    }
    Buzzer* buzzer = Buzzer_init(BUZZER_GPIO);
    if (buzzer == NULL) {
        free(pir);
        gpioTerminate();
        return 1;
    }

    // Main event loop
    while (1) {
        // Read the PIR sensor state
        if (PIRSensor_readSensor(pir) == 1) {
            // Motion detected!
            printf("Motion detected!\n");

            // Activate the buzzer
            Buzzer_activate(buzzer);

            // Log the event to a file
            FILE* log_file = fopen("motion_log.txt", "a");
            if (log_file != NULL) {
                char timestamp[20];
                getTimestamp(timestamp);
                fprintf(log_file, "%s - Motion detected\n", timestamp);
                fclose(log_file);
            } else {
                fprintf(stderr, "Error opening log file\n");
            }

            // Wait for 2 seconds
            gpioDelay(2000); // Wait for 2 seconds (2000 milliseconds)

            // Deactivate the buzzer
            Buzzer_deactivate(buzzer);

            printf(" - Buzzer deactivated.\n");
        }

        // Small delay to prevent busy-waiting
        gpioDelay(100); // Check every 100 milliseconds
    }

    // Clean up pigpio (this part is never reached in this example due to the infinite loop)
    free(pir);
    free(buzzer);
    gpioTerminate();

    return 0;
}

