        fprintf(stderr, "Failed to initialize pigpio library.\n");
        exit(1);
    }

    /* Initialize the wiringPi library. */
    if (wiringPiSetup() < 0) {
        fprintf(stderr, "Failed to initialize wiringPi library.\n");
        pigpio_stop();
        exit(1);
    }

    /* Initialize the wiringPi SPI library. */
    if (wiringPiSPISetup(0, 1000000) < 0) {
        fprintf(stderr, "Failed to initialize wiringPi SPI library.\n");
        pigpio_stop();
        exit(1);
    }

    /* Initialize the GPIO pins. */
