#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define GPIO pins
#define PIR_PIN 4
#define BUZZER_PIN 18

// Debounce time in milliseconds
#define DEBOUNCE_TIME 500

// Buzzer duration in milliseconds
#define BUZZER_DURATION 500

// Global flag to indicate program termination
volatile int terminate = 0;

// Function prototypes
void motion_detected_callback(int gpio, int level, uint32_t tick);
void activate_buzzer(int duration_ms);
void log_motion_event();
void signal_handler(int signal);

// Structure to hold program state
typedef struct {
    FILE *log_file;
} ProgramState;

ProgramState state;

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Open log file
    state.log_file = fopen("motion_log.txt", "a");
    if (state.log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        gpioTerminate();
        return 1;
    }

    // Register signal handler for graceful termination
    signal(SIGINT, signal_handler);

    // Set up interrupt handler for PIR sensor
    gpioSetAlertFunc(PIR_PIN, motion_detected_callback);

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop (keep the program running until a signal is received)
    while (!terminate) {
        gpioDelay(100); // Reduce CPU usage
    }

    // Cleanup
    fclose(state.log_file);
    gpioTerminate();

    printf("Motion detection system stopped.\n");

    return 0;
}

// Interrupt handler for motion detection
void motion_detected_callback(int gpio, int level, uint32_t tick) {
    static uint32_t last_tick = 0;
    uint32_t current_tick = gpioTick();

    if (level == 1 && (current_tick - last_tick > DEBOUNCE_TIME * 1000)) { // Debounce
        printf("Motion detected!\n");
        activate_buzzer(BUZZER_DURATION);
        log_motion_event();
        last_tick = current_tick;
    }
}

// Function to activate the buzzer
void activate_buzzer(int duration_ms) {
    gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
    gpioDelay(duration_ms);    // Wait for specified duration
    gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
}

// Function to log motion events with timestamps
void log_motion_event() {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(state.log_file, "%s: Motion detected\n", timestamp);
    fflush(state.log_file); // Ensure immediate write to file
}

// Signal handler for graceful termination
void signal_handler(int signal) {
    printf("Signal received, terminating...\n");
    terminate = 1;
}
