    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(IR_SENSOR_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Set initial servo position to IDLE
    set_servo_pulse(IDLE_PULSE_WIDTH);
    gpioDelay(1000); // Allow servo to reach the position

    // Set up signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Bird feeder control program started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        int sensor_value = read_ir_sensor();
        if (sensor_value == 0) { // Obstacle detected (KY-032 outputs LOW)
            printf("Obstacle detected! Feeding bird.\n");
            if (set_servo_pulse(FEED_PULSE_WIDTH) == 0) {
                log_event("Feeding");
                gpioDelay(2000); // Delay to allow bird to eat
                set_servo_pulse(IDLE_PULSE_WIDTH);
            }
        } else if (sensor_value < 0) {
            fprintf(stderr, "Error reading sensor, exiting.\n");
            break;
        }
        gpioDelay(500); // Delay to avoid excessive CPU usage
    }

    // Clean up and terminate pigpio
    set_servo_pulse(IDLE_PULSE_WIDTH);
    gpioTerminate();
    printf("Program terminated.\n");

    return 0;
}
