// Define GPIO pins using WiringPi numbering
#define PIR_PIN 25
#define BUZZER_PIN 24

// Debounce time in milliseconds
#define DEBOUNCE_TIME 200

// Global variable to store the last interrupt time
static volatile unsigned long lastInterruptTime = 0;

// Function to initialize GPIO pins
int initializeGPIO() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed. Please check your setup.\n");
        return -1; // Indicate failure
    }

    pinMode(PIR_PIN, INPUT);
    pinMode(BUZZER_PIN, OUTPUT);

    return 0; // Indicate success
}

// Function to control the buzzer
void buzz(int duration_ms) {
    digitalWrite(BUZZER_PIN, HIGH); // Activate buzzer
    delay(duration_ms);              // Delay for specified duration
    digitalWrite(BUZZER_PIN, LOW);  // Deactivate buzzer
}

// Interrupt handler function
void interruptHandler() {
    unsigned long currentTime = millis();

    // Debounce check
    if (currentTime - lastInterruptTime > DEBOUNCE_TIME) {
        buzz(500); // Activate buzzer for 500ms
        lastInterruptTime = currentTime;
    }
}

int main() {
    // Initialize GPIO pins
    if (initializeGPIO() == -1) {
        return 1; // Exit if initialization failed
    }

    // Register interrupt handler for PIR sensor
    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, interruptHandler) < 0) {
        fprintf(stderr, "Unable to setup ISR. Exiting.\n");
        return 1; // Exit if ISR setup failed
    }

    printf("Motion-activated buzzer system running. Press Ctrl+C to exit.\n");

    // Keep the program running
    while (1) {
        delay(100); // Small delay to reduce CPU usage
    }

    return 0;
}

