#include <wiringPi.h>

#define PIR_PIN 25
#define BUZZER_PIN 24

void trigger_buzzer()
{
    int buzzer_state = digitalRead(BUZZER_PIN);

    if (buzzer_state == 1) {
        printf("Buzzer already triggered\n");
        return;
    }

    printf("Buzzer triggered\n");
    digitalWrite(BUZZER_PIN, 1);
    delay(2000);
    digitalWrite(BUZZER_PIN, 0);
}

void interrupt_handler(void)
{
    trigger_buzzer();
}

void init_gpio()
{
    if (wiringPiSetup() == -1) {
        printf("Unable to setup wiringPi\n");
        exit(1);
    }
    pinMode(PIR_PIN, INPUT);
    pinMode(BUZZER_PIN, OUTPUT);
    digitalWrite(BUZZER_PIN, 0);
    wiringPiISR(PIR_PIN, INT_EDGE_BOTH, &interrupt_handler);
}

int main(int argc, char *argv[])
{
    init_gpio();
    while (1) {}
    return 0;
}
