// Define sensor addresses
int sensor_addresses[] = {0x44, 0x45};
#define NUM_SENSORS (sizeof(sensor_addresses) / sizeof(sensor_addresses[0]))

// Define measurement command (high repeatability)
#define MEASUREMENT_COMMAND_HIGH 0x2C06

// Define retry attempts
#define MAX_RETRIES 3

// Define delay between retries (in milliseconds)
#define RETRY_DELAY 10

// Define data structure for sensor data
struct sensor_data {
    int sensor_id; // I2C address
    long timestamp_sec;
    long timestamp_usec;
    float temperature;
    float humidity;
};

// Global variable for program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    fprintf(stderr, "\nCaught signal, exiting gracefully...\n");
}

// Function to calculate CRC
uint8_t crc8(const uint8_t *data, int len) {
    const uint8_t POLYNOMIAL = 0x31; // Standard CRC-8 polynomial
    uint8_t crc = 0xFF;

    for (int j = 0; j < len; ++j) {
        crc ^= data[j];
        for (int i = 0; i < 8; ++i) {
            crc = (crc & 0x80) ? ((crc << 1) ^ POLYNOMIAL) : (crc << 1);
        }
    }
    return crc;
}

// Function to read sensor data from SHT31-D
int read_sensor_data(int i2c_handle, struct sensor_data *data) {
    uint8_t write_data[2];
    uint8_t read_data[6];
    int result;

    // Send measurement command
    write_data[0] = (MEASUREMENT_COMMAND_HIGH >> 8) & 0xFF;
    write_data[1] = MEASUREMENT_COMMAND_HIGH & 0xFF;

    result = i2cWriteDevice(i2c_handle, (char *)write_data, 2);
    if (result != 0) {
        fprintf(stderr, "Error writing to I2C device: %d\n", result);
        return -1;
    }

    gpioDelay(20); // Wait for measurement (adjust as needed)

    // Read 6 bytes of data (Temp MSB, Temp LSB, Temp CRC, Hum MSB, Hum LSB, Hum CRC)
    result = i2cReadDevice(i2c_handle, (char *)read_data, 6);
    if (result != 6) {
        fprintf(stderr, "Error reading from I2C device: %d\n", result);
        return -1;
    }

    // CRC check for temperature data
    if (crc8(read_data, 2) != read_data[2]) {
        fprintf(stderr, "Temperature CRC check failed\n");
        return -1;
    }

    // CRC check for humidity data
    if (crc8(read_data + 3, 2) != read_data[5]) {
        fprintf(stderr, "Humidity CRC check failed\n");
        return -1;
    }

    // Convert raw data to temperature and humidity
    int32_t raw_temperature = (read_data[0] << 8) | read_data[1];
    int32_t raw_humidity = (read_data[3] << 8) | read_data[4];

    data->temperature = -45 + (175 * (float)raw_temperature / 65535.0);
    data->humidity = 100 * (float)raw_humidity / 65535.0;

    return 0;
}

// Function to log data to JSON file
int log_data_to_json(const struct sensor_data *data, int num_sensors, const char *filename) {
    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s\n", filename);
        return -1;
    }

    // Append the JSON data to the file
    fprintf(fp, "%s{", (ftell(fp) == 0) ? "[" : ",");
    fprintf(fp, "\"sensor_id\": %d, ", data->sensor_id);
    fprintf(fp, "\"timestamp_sec\": %ld, ", data->timestamp_sec);
    fprintf(fp, "\"timestamp_usec\": %ld, ", data->timestamp_usec);
    fprintf(fp, "\"temperature\": %.2f, ", data->temperature);
    fprintf(fp, "\"humidity\": %.2f}", data->humidity);

    fclose(fp);
    return 0;
}

int main() {
    int i2c_handle[NUM_SENSORS];
    struct sensor_data data[NUM_SENSORS];
    int i, retries, result;
    struct timeval tv;

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Open I2C connections for each sensor
    for (i = 0; i < NUM_SENSORS; i++) {
        i2c_handle[i] = i2cOpen(1, sensor_addresses[i], 0); // I2C bus 1
        if (i2c_handle[i] < 0) {
            fprintf(stderr, "Error opening I2C device at address 0x%02X: %d\n", sensor_addresses[i], i2c_handle[i]);
            i2c_handle[i] = -1; // Mark as invalid
        }
    }

    // Main loop
    while (program_running) {
        for (i = 0; i < NUM_SENSORS; i++) {
            if (i2c_handle[i] >= 0) { // Only process valid handles
                // Retry mechanism for reading sensor data
                retries = 0;
                result = -1; // Initialize result to error state
                while (retries < MAX_RETRIES && result != 0) {
                    // Read timestamp
                    gettimeofday(&tv, NULL);
                    data[i].timestamp_sec = tv.tv_sec;
                    data[i].timestamp_usec = tv.tv_usec;
                    data[i].sensor_id = sensor_addresses[i];
                    result = read_sensor_data(i2c_handle[i], &data[i]);
                    if (result != 0) {
                        fprintf(stderr, "Error reading sensor data from 0x%02X, retrying (%d/%d)\n", sensor_addresses[i], retries + 1, MAX_RETRIES);
                        gpioDelay(RETRY_DELAY); // Wait before retrying
                        retries++;
                    }
                }

                if (result == 0) {
                    // Log data to JSON file
                    if (log_data_to_json(&data[i], 1, "environmental_data.json") != 0) {
                        fprintf(stderr, "Error logging data to file\n");
                    }
                } else {
                    fprintf(stderr, "Failed to read sensor data from 0x%02X after %d retries\n", sensor_addresses[i], MAX_RETRIES);
                }
            }
        }

        gpioDelay(5000); // Read data every 5 seconds
    }

    // Close I2C connections
    for (i = 0; i < NUM_SENSORS; i++) {
        if (i2c_handle[i] >= 0) {
            i2cClose(i2c_handle[i]);
        }
    }

    // Finalize pigpio library
    gpioTerminate();

    // Add closing bracket to JSON file if any data was logged
    FILE *fp = fopen("environmental_data.json", "a");
    if (fp != NULL) {
        fseek(fp, 0, SEEK_END);
        long file_size = ftell(fp);
        if (file_size > 0) {
            fprintf(fp, "]");
        }
        fclose(fp);
    }

    return 0;
}

