void init_pwm() {
    int fd;

    if ((fd = open("/dev/mem", O_RDWR | O_SYNC)) < 0) {
        printf("Error opening /dev/mem\n");
        exit(1);
    }
    if (mlockall(MCL_CURRENT | MCL_FUTURE) < 0) {
        printf("Error locking memory\n");
        exit(1);
    }
    wiringPiSetupGpio();
    pinMode(PWM_FAN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(PWM_MAX);
    pwmWrite(PWM_FAN, PWM_MIN);
}

int16_t read_i2c_word(uint8_t reg) {
    int16_t data = 0;
    if (wiringPiI2CReadReg16(LM75_I2C_ADDR, reg) < 0) {
        printf("I2C read error\n");
        return -1;
    }
    data = wiringPiI2CReadReg16(LM75_I2C_ADDR, reg) >> 8;
    return data;
}

void set_pwm_duty_cycle(uint8_t pwm, uint8_t duty_cycle) {
    if (duty_cycle < PWM_MIN) {
        duty_cycle = PWM_MIN;
    } else if (duty_cycle > PWM_MAX) {
        duty_cycle = PWM_MAX;
    }
    pwmWrite(pwm, duty_cycle);
}

void main() {
    time_t t;
    struct tm *tm;
    char time_str[50];
    uint8_t duty_cycle = PWM_MIN;
    double temp = 0;
    double target = 25;
    double tos = 25;
    double thys = 25;
    double fan_duty = 0;

    if (wiringPiSetup() < 0) {
        printf("WiringPi setup failed\n");
        exit(1);
    }

    if (wiringPiI2CSetup(LM75_I2C_ADDR) < 0) {
        printf("I2C setup failed\n");
        exit(1);
    }

    if (wiringPiI2CReadReg8(LM75_I2C_ADDR, LM75_CONF) & 0x01) {
        printf("Sensor is in shutdown mode, use the config register to set it to ON\n");
        exit(1);
    }

    init_pwm();

    while (1) {
        temp = read_i2c_word(LM75_TEMP) / 256.0;
        tos = read_i2c_word(LM75_TOS) / 256.0;
        thys = read_i2c_word(LM75_THYS) / 256.0;

        time(&t);
        tm = localtime(&t);
        strftime(time_str, 50, "%H:%M:%S", tm);

        if (temp > LM75_TEMP_MAX) {
            printf("Temperature is too high, shutdown fan\n");
            set_pwm_duty_cycle(PWM_FAN, 0);
            fan_duty = 0;
        } else {
            if (temp <= LM75_TEMP_MIN) {
                printf("Temperature is too low, increase fan speed\n");
                fan_duty = (temp - LM75_TEMP_MIN) / (LM75_TEMP_MAX - LM75_TEMP_MIN) * (PWM_MAX - PWM_MIN) + PWM_MIN;
            } else {
                fan_duty = (temp - LM75_TEMP_MIN) / (LM75_TEMP_MAX - LM75_TEMP_MIN) * (PWM_MAX - PWM_MIN) + PWM_MIN;
            }
            set_pwm_duty_cycle(PWM_FAN, fan_duty);
        }

        printf("Temperature: %f\n", temp);
        printf("Target: %f\n", target);
        printf("Thermostat: %f\n", tos);
        printf("Hysteresis: %f\n", thys);
        printf("Fan speed: %f\n", fan_duty);
        printf("Time: %s\n", time_str);

        FILE *log_file;
        int ret = 0;
        if ((log_file = fopen("cooling_log.txt", "a")) == NULL) {
            printf("Error opening log file\n");
            exit(1);
        }

        ret = fprintf(log_file, "%s %f %f %f %f\n", time_str, temp, target, tos, thys);
        if (ret < 0) {
            printf("Error writing to log file\n");
            exit(1);
        }

        fclose(log_file);
        sleep(1);
    }
}
