#define SENSOR2_ADDR 0x30
#define SENSOR3_ADDR 0x31

#define WARNING_THRESHOLD 200 // mm

// Global variables (minimize usage)
static FILE *log_file = NULL;
static volatile int running = 1;

// Function prototypes
