    if (model_id != 0xEE) {
        fprintf(stderr, "Error: Invalid model ID (0x%02X) for sensor at address 0x%02X\n", model_id, address);
        close(fd);
        return -1;
    }
    wiringPiI2CWriteReg8(fd, VL53L1X_REG_INTERMEASUREMENT_PERIOD, 0x0B); // Example setting

