// Trigger a warning if an object is too close
void trigger_warning(int sensor_id, int distance) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    char message[100];
    snprintf(message, sizeof(message), "%s - WARNING: Sensor %d - Object detected at %d mm!\n", timestamp, sensor_id, distance);

    printf("%s", message);
    log_message(message);
}

// Log a message to the distance_log.txt file
void log_message(const char *message) {
    if (log_file != NULL) {
        fprintf(log_file, "%s", message);
        fflush(log_file); // Ensure immediate write
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
