void log_distance(int distance) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s, Distance: %d mm\n", s, distance);
    fclose(fp);
}

// Checks if the distance is below the threshold and logs a warning
void check_distance_and_warn(int distance) {
    if (distance < DISTANCE_THRESHOLD) {
        printf("Warning: Object is close (%d mm)!\n", distance);
        log_distance(distance);
    }
}

int main() {
    int distance;
    int status;

    // Register signal handler for Ctrl+C
    signal(SIGINT, cleanup);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(I2C_BUS, VL53L1X_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize VL53L1X sensor
    if (init_vl53l1x() != 0) {
        fprintf(stderr, "VL53L1X initialization failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    printf("VL53L1X sensor initialized successfully.\n");

    // Main loop
    while (1) {
        status = read_distance(i2c_handle, &distance);
        if (status == 0) {
            printf("Distance: %d mm\n", distance);
            log_distance(distance);
            check_distance_and_warn(distance);
        } else {
            fprintf(stderr, "Error reading distance\n");
        }

        gpioDelay(100); // Delay for 100ms
    }

    return 0;
}
