#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <unistd.h>
#include <signal.h>
#include <string.h>
#include <stdbool.h>

// Configuration
#define SPI_CHANNEL 0
#define SPI_BAUD 500000
#define MCP3008_CE 8

#define RELAY_1 17
#define RELAY_2 18
#define RELAY_3 27
#define RELAY_4 22

#define MIN_MOISTURE_RAW 300  // Example dry value
#define MAX_MOISTURE_RAW 700  // Example wet value
#define MOISTURE_THRESHOLD 30 // Percentage
#define WATERING_DURATION 60  // Seconds

volatile sig_atomic_t program_running = 1;
int spi_handle = -1;
FILE *log_file = NULL;

// Function Prototypes
int spi_init();
int read_mcp3008_channel(int channel);
float map_moisture_to_percentage(int raw_value);
bool should_water(int zone_number, float moisture_percentage, int threshold);
void activate_relay(int gpio);
void deactivate_relay(int gpio);
void irrigate_zone(int zone_number, int watering_duration_seconds);
void run_irrigation_cycle();
void log_irrigation_event(int zone_number, time_t start_time, int duration_seconds);
void signal_handler(int signal);
void cleanup();

// SPI Communication
int spi_init() {
    spi_handle = spiOpen(SPI_CHANNEL, SPI_BAUD, 0); // Mode 0
    if (spi_handle < 0) {
        fprintf(stderr, "Error opening SPI channel: %d\n", spi_handle);
        return -1;
    }
    return 0;
}

int read_mcp3008_channel(int channel) {
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Invalid MCP3008 channel: %d\n", channel);
        return -1;
    }

    char spi_tx_buf[3];
    char spi_rx_buf[3];

    spi_tx_buf[0] = 0x01; // Start bit
    spi_tx_buf[1] = ((channel & 0x07) << 4) | 0x80; // SGL/DIFF = 1, D2=D1=D0=channel
    spi_tx_buf[2] = 0x00;

    if (spiXfer(spi_handle, spi_tx_buf, spi_rx_buf, 3) == 3) {
        int adc_value = ((spi_rx_buf[1] & 0x03) << 8) + spi_rx_buf[2];
        return adc_value;
    } else {
        fprintf(stderr, "SPI transfer failed for channel %d\n", channel);
        return -1;
    }
}

// Soil Moisture Sensing
float map_moisture_to_percentage(int raw_value) {
    float percentage = 100.0 - ((float)(raw_value - MIN_MOISTURE_RAW) / (float)(MAX_MOISTURE_RAW - MIN_MOISTURE_RAW)) * 100.0;
    if (percentage < 0.0) percentage = 0.0;
    if (percentage > 100.0) percentage = 100.0;
    return percentage;
}

bool should_water(int zone_number, float moisture_percentage, int threshold) {
    return moisture_percentage < threshold;
}

// Relay Control
void activate_relay(int gpio) {
    gpioWrite(gpio, 1); // HIGH to activate
    printf("Activated relay on GPIO %d\n", gpio);
}

void deactivate_relay(int gpio) {
    gpioWrite(gpio, 0); // LOW to deactivate
    printf("Deactivated relay on GPIO %d\n", gpio);
}

// Irrigation Logic
void irrigate_zone(int zone_number, int watering_duration_seconds) {
    int relay_gpio;
    switch (zone_number) {
        case 1: relay_gpio = RELAY_1; break;
        case 2: relay_gpio = RELAY_2; break;
        case 3: relay_gpio = RELAY_3; break;
        case 4: relay_gpio = RELAY_4; break;
        default: fprintf(stderr, "Invalid zone number: %d\n", zone_number); return;
    }

    time_t start_time = time(NULL);
    activate_relay(relay_gpio);
    sleep(watering_duration_seconds);
    deactivate_relay(relay_gpio);
    log_irrigation_event(zone_number, start_time, watering_duration_seconds);
}

void run_irrigation_cycle() {
    int zones[] = {1, 2, 3, 4};
    int num_zones = sizeof(zones) / sizeof(zones[0]);

    for (int i = 0; i < num_zones; i++) {
        int zone_number = zones[i];
        int raw_moisture = read_mcp3008_channel(zone_number - 1); // MCP3008 channels are 0-indexed

        if (raw_moisture < 0) {
            fprintf(stderr, "Error reading moisture for zone %d\n", zone_number);
            continue;
        }

        float moisture_percentage = map_moisture_to_percentage(raw_moisture);
        printf("Zone %d: Moisture level = %.2f%%\n", zone_number, moisture_percentage);

        if (should_water(zone_number, moisture_percentage, MOISTURE_THRESHOLD)) {
            printf("Watering zone %d\n", zone_number);
            irrigate_zone(zone_number, WATERING_DURATION);
        }
    }
}

// JSON Logging
void log_irrigation_event(int zone_number, time_t start_time, int duration_seconds) {
    struct tm *tm_info;
    char timestamp[20];

    tm_info = localtime(&start_time);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", tm_info);

    if (log_file == NULL) {
        log_file = fopen("irrigation_log.json", "a");
        if (log_file == NULL) {
            fprintf(stderr, "Error opening log file!\n");
            return;
        }
    }

    fprintf(log_file, "{\"timestamp\": \"%s\", \"zone\": %d, \"duration\": %d}\n", timestamp, zone_number, duration_seconds);
    fflush(log_file); // Ensure data is written to disk
}

// Signal Handling
void signal_handler(int signal) {
    printf("Received signal %d, shutting down...\n", signal);
    program_running = 0;
}

// Cleanup
void cleanup() {
    printf("Cleaning up...\n");
    // Deactivate all relays
    deactivate_relay(RELAY_1);
    deactivate_relay(RELAY_2);
    deactivate_relay(RELAY_3);
    deactivate_relay(RELAY_4);

    // Close SPI
    if (spi_handle >= 0) {
        spiClose(spi_handle);
    }

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    gpioTerminate();
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes for relays
    gpioSetMode(RELAY_1, PI_OUTPUT);
    gpioSetMode(RELAY_2, PI_OUTPUT);
    gpioSetMode(RELAY_3, PI_OUTPUT);
    gpioSetMode(RELAY_4, PI_OUTPUT);

    // Initialize SPI
    if (spi_init() != 0) {
        fprintf(stderr, "SPI initialization failed\n");
        cleanup();
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Smart Irrigation System started\n");

    while (program_running) {
        run_irrigation_cycle();
        sleep(60); // Check every minute
    }

    cleanup();
    return 0;
}

