    unsigned char spi_tx_buf[3];
    unsigned char spi_rx_buf[3];

    // MCP3008 configuration: Start bit, single-ended mode, channel selection, don't care
    spi_tx_buf[0] = 0x01; // Start bit
    spi_tx_buf[1] = (0x08 | (channel << 4)); // Single-ended, channel selection
    spi_tx_buf[2] = 0x00; // Don't care

    if (spiXfer(spi_handle, spi_tx_buf, spi_rx_buf, 3) != 0) {
        perror("SPI communication error");
        return -1; // Indicate error
    }

    // Extract the ADC value from the response
    int adc_value = ((spi_rx_buf[1] & 0x03) << 8) + spi_rx_buf[2];

    return adc_value;
}

