    fprintf(log_file, "[%s] %s\n", timestamp, message);
    fflush(log_file); // Ensure the message is written immediately
}

// Interrupt handler function
void vibration_detected(int gpio, int level, uint32_t tick, void *user_data) {
    (void)level; // Suppress unused parameter warning
    (void)tick;  // Suppress unused parameter warning

    callback_data_t *data = (callback_data_t*)user_data;
    if (gpio == data->gpio_pin) {
        log_message("Vibration detected! Initiating shutdown...");
        system("sudo shutdown -h now");
    }
}

