} sensor_args_t;

// Global Variables
FILE *log_file;
volatile sig_atomic_t program_running = 1;
pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;
int fan_state = 0; // 0: off, 1: on

int main(int argc, char *argv[]) {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO for fan
    gpioSetMode(FAN_GPIO, PI_OUTPUT);

    // Open log file
    log_file = fopen(LOG_FILE_PATH, "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Write CSV header if the file is new
    fseek(log_file, 0, SEEK_END);
    long file_size = ftell(log_file);
    if (file_size == 0) {
        fprintf(log_file, "Timestamp,Sensor ID,Temperature (C),Humidity (%%)\n");
    }

    // Set up signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize I2C handles and create sensor threads
    pthread_t threads[NUM_SENSORS];
    sensor_args_t sensor_args[NUM_SENSORS];

    for (int i = 0; i < NUM_SENSORS; i++) {
        int i2c_handle = i2cOpen(I2C_BUS, AHT20_ADDR, 0); //Flags = 0, for default operation
        if (i2c_handle < 0) {
            fprintf(stderr, "Error opening I2C channel for sensor %d: %d\n", i + 1, i2c_handle);
            program_running = 0; // Stop other threads from starting
            break;
        }

        // Initialize AHT20 sensor (trigger measurement)
        char init_cmd[3] = {0xBE, 0x08, 0x00}; // Calibration enable command
        if (i2cWriteDevice(i2c_handle, init_cmd, 3) != 0) {
            fprintf(stderr, "Error initializing AHT20 sensor %d\n", i + 1);
            i2cClose(i2c_handle);
            program_running = 0;
            break;
        }
        gpioDelay(20); // Wait for initialization

        sensor_args[i].sensor_id = i + 1;
        sensor_args[i].i2c_handle = i2c_handle;

        if (pthread_create(&threads[i], NULL, sensor_thread, &sensor_args[i]) != 0) {
            perror("Error creating sensor thread");
            program_running = 0;
            i2cClose(i2c_handle);
            break;
        }
    }

    // Main loop (optional - for other tasks)
    while (program_running) {
        sleep(1);
    }

    // Join threads and clean up
    for (int i = 0; i < NUM_SENSORS; i++) {
        if (threads[i] != 0) {
            pthread_join(threads[i], NULL);
        }
    }

    gpioTerminate();
    return 0;
}

void *sensor_thread(void *arg) {
    sensor_args_t *sensor_args = (sensor_args_t *)arg;
    int sensor_id = sensor_args->sensor_id;
    int i2c_handle = sensor_args->i2c_handle;
    float temperature, humidity;

    while (program_running) {
        if (read_aht20(i2c_handle, &temperature, &humidity) == 0) {
            log_data(sensor_id, temperature, humidity);

            // Fan control logic
            static float max_humidity = 0.0;
            static float min_humidity = 100.0;

            // Update maximum and minimum humidity values from all sensors
            if (humidity > max_humidity) {
                max_humidity = humidity;
            }
            if (humidity < min_humidity) {
                min_humidity = humidity;
            }

            // Turn on the fan if any sensor exceeds the high threshold
            if (max_humidity > HUMIDITY_HIGH_THRESHOLD && fan_state == 0) {
                control_fan(FAN_GPIO, 1);
                fan_state = 1;
            }

            // Turn off the fan only when all sensors are below the low threshold
            if (min_humidity < HUMIDITY_LOW_THRESHOLD && fan_state == 1) {
                control_fan(FAN_GPIO, 0);
                fan_state = 0;
            }

            // Reset max and min humidity for the next cycle
            max_humidity = 0.0;
            min_humidity = 100.0;
        } else {
            fprintf(stderr, "Error reading sensor %d\n", sensor_id);
        }
        gpioDelay(2000); // Poll every 2 seconds
    }

    i2cClose(i2c_handle);
    pthread_exit(NULL);
}

int read_aht20(int i2c_handle, float *temperature, float *humidity) {
    unsigned char data[6];
    char cmd[3] = {0xAC, 0x33, 0x00}; // Trigger measurement command

    // Trigger measurement
    if (i2cWriteDevice(i2c_handle, cmd, 3) != 0) {
        fprintf(stderr, "I2C write failed: trigger measurement\n");
        return -1;
    }
    gpioDelay(80); // Wait for measurement (at least 75ms)

    // Read data
    if (i2cReadDevice(i2c_handle, (char *)data, 6) != 6) {
        fprintf(stderr, "I2C read failed\n");
        return -1;
    }

    // Check CRC
    if (crc8(data, 5) != data[5]) {
        fprintf(stderr, "CRC check failed\n");
        return -1;
    }

    // Check status bit (calibration status)
    if ((data[0] & 0x80) != 0) {
        fprintf(stderr, "Sensor not calibrated\n");
        return -1;
    }

    // Convert data
    unsigned long humidity_raw = ((unsigned long)data[1] << 12) | ((unsigned long)data[2] << 4) | (data[3] >> 4);
    unsigned long temperature_raw = ((unsigned long)data[3] & 0x0F) << 16 | ((unsigned long)data[4] << 8) | data[5];

    *humidity = ((float)humidity_raw / 0x100000) * 100;
    *temperature = ((float)temperature_raw / 0x100000) * 200 - 50;

    return 0;
}

unsigned char crc8(const unsigned char *data, size_t len) {
    unsigned char crc = 0xFF;
    for (size_t i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) {
                crc = (crc << 1) ^ 0x31; // Polynomial X^8 + X^5 + X^4 + 1
            } else {
                crc <<= 1;
            }
        }
    }
    return crc;
}

void control_fan(int gpio_pin, int fan_state) {
    gpioWrite(gpio_pin, fan_state);
    printf("Fan state: %d\n", fan_state);
}

void log_data(int sensor_id, float temperature, float humidity) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    pthread_mutex_lock(&log_mutex);
    fprintf(log_file, "%s,%d,%.2f,%.2f\n", timestamp, sensor_id, temperature, humidity);
    fflush(log_file);
    pthread_mutex_unlock(&log_mutex);

    printf("%s, Sensor %d: Temperature = %.2f C, Humidity = %.2f %%\n", timestamp, sensor_id, temperature, humidity);
}

void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    program_running = 0;

    // Disable the fan
    control_fan(FAN_GPIO, 0);

    // Close the log file
    if (log_file != NULL) {
        fclose(log_file);
    }
}

