#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <unistd.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Constants
#define I2C_BUS 1
#define AHT20_ADDR 0x38
#define FAN_GPIO 18
#define HUMIDITY_THRESHOLD 70.0
#define MEASUREMENT_INTERVAL 5 // seconds

// AHT20 Commands
#define AHT20_INIT 0xBE
#define AHT20_RESET 0xBA
#define AHT20_TRIGGER_MEASURE 0xAC
#define AHT20_READ_DATA 0xC0

// Data structure for sensor data
typedef struct {
    float temperature;
    float humidity;
} SensorData;

// Global variables
int i2c_handle;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int init_i2c();
int aht20_init();
int aht20_read_data(uint8_t *data);
int aht20_trigger_measurement();
SensorData process_sensor_data(uint8_t *data);
void control_fan(float humidity);
void log_data(SensorData data);
void signal_handler(int signal);

// Function to initialize the I2C interface
int init_i2c() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    i2c_handle = i2cOpen(I2C_BUS, AHT20_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return -1;
    }

    return 0;
}

// Function to initialize the AHT20 sensor
int aht20_init() {
    uint8_t init_cmd[3] = {AHT20_INIT, 0xBE, 0x08};
    int result = i2cWriteDevice(i2c_handle, (char *)init_cmd, 3);
    if (result != 0) {
        fprintf(stderr, "AHT20 initialization failed: %d\n", result);
        return -1;
    }

    gpioDelay(10); // Wait for initialization to complete
    return 0;
}

// Function to trigger a measurement on the AHT20 sensor
int aht20_trigger_measurement() {
    uint8_t measure_cmd[3] = {AHT20_TRIGGER_MEASURE, 0x33, 0x00};
    int result = i2cWriteDevice(i2c_handle, (char *)measure_cmd, 3);
    if (result != 0) {
        fprintf(stderr, "AHT20 measurement trigger failed: %d\n", result);
        return -1;
    }

    gpioDelay(80); // Wait for measurement to complete (adjust as needed)
    return 0;
}

// Function to read data from the AHT20 sensor
int aht20_read_data(uint8_t *data) {
    int result = i2cReadDevice(i2c_handle, (char *)data, 6);
    if (result != 6) {
        fprintf(stderr, "AHT20 read failed: %d\n", result);
        return -1;
    }
    return 0;
}

// Function to process the sensor data and calculate temperature and humidity
SensorData process_sensor_data(uint8_t *data) {
    SensorData sensor_data;
    uint32_t humidity_raw = ((uint32_t)data[1] << 12) | ((uint32_t)data[2] << 4) | (data[3] >> 4);
    uint32_t temperature_raw = ((uint32_t)(data[3] & 0x0F) << 16) | ((uint32_t)data[4] << 8) | data[5];

    sensor_data.humidity = ((float)humidity_raw / 0x100000) * 100;
    sensor_data.temperature = ((float)temperature_raw / 0x100000) * 200 - 50;

    return sensor_data;
}

// Function to control the cooling fan based on humidity
void control_fan(float humidity) {
    if (humidity > HUMIDITY_THRESHOLD) {
        gpioWrite(FAN_GPIO, 1); // Turn fan on
        printf("Fan ON (Humidity: %.2f%%)\n", humidity);
    } else {
        gpioWrite(FAN_GPIO, 0); // Turn fan off
        printf("Fan OFF (Humidity: %.2f%%)\n", humidity);
    }
}

// Function to log sensor data to a file
void log_data(SensorData data) {
    FILE *fp = fopen("environmental_data.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, Temperature: %.2f, Humidity: %.2f\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            data.temperature, data.humidity);
    fclose(fp);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
    gpioWrite(FAN_GPIO, 0); // Turn off fan
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize signal handling
    signal(SIGINT, signal_handler);

    // Initialize I2C
    if (init_i2c() != 0) {
        return 1;
    }

    // Initialize AHT20 sensor
    if (aht20_init() != 0) {
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure FAN_GPIO as output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);

    uint8_t sensor_data[6];

    while (program_running) {
        // Trigger measurement
        if (aht20_trigger_measurement() != 0) {
            fprintf(stderr, "Failed to trigger measurement, retrying...\n");
            gpioDelay(1000); // Wait before retrying
            continue;
        }

        // Read sensor data
        if (aht20_read_data(sensor_data) != 0) {
            fprintf(stderr, "Failed to read sensor data, retrying...\n");
            gpioDelay(1000); // Wait before retrying
            continue;
        }

        // Process sensor data
        SensorData processed_data = process_sensor_data(sensor_data);

        // Control fan based on humidity
        control_fan(processed_data.humidity);

        // Log data
        log_data(processed_data);

        // Print sensor readings
        printf("Temperature: %.2f °C, Humidity: %.2f %%\n", processed_data.temperature, processed_data.humidity);

        gpioDelay(MEASUREMENT_INTERVAL * 1000); // Wait for measurement interval
    }

    return 0;
}
