    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(log_file, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event);
    fflush(log_file); // Ensure the log is written immediately
  }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
  program_running = 0;
  printf("\nCaught signal %d, exiting gracefully...\n", signal);
  log_event("Program terminated.");

  // Close the log file
  if (log_file != NULL) {
    fclose(log_file);
  }

  // Deactivate relays
  digitalWrite(DOOR_UP_PIN, LOW);
  digitalWrite(DOOR_DOWN_PIN, LOW);

  exit(0);
}

int main() {
  // Initialize wiringPi
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "wiringPiSetup failed, exiting...\n");
    return 1;
  }

  // Set GPIO pin modes
  pinMode(DOOR_UP_PIN, OUTPUT);
  pinMode(DOOR_DOWN_PIN, OUTPUT);
  pinMode(SENSOR_1_PIN, INPUT);
  pinMode(SENSOR_2_PIN, INPUT);

  // Initialize log file
  log_file = fopen(LOG_FILE, "a");
  if (log_file == NULL) {
    fprintf(stderr, "Failed to open log file, logging to console instead.\n");
  }

  // Register signal handler
  signal(SIGINT, signal_handler);

  printf("Smart Chicken Coop Door Control System\n");
  log_event("Program started.");

  // Main loop
  while (program_running) {
    // Read sensor values
    int sensor1_value = read_sensor(SENSOR_1_PIN);
    int sensor2_value = read_sensor(SENSOR_2_PIN);

    // Determine door state based on sensor readings
    int door_state = 1; // Assume up state initially
    if (sensor1_value || sensor2_value) {
      door_state = 0; // Down state if any sensor detects an obstacle
    }

    // Control the door if the state has changed
    if (door_state != (digitalRead(DOOR_UP_PIN) == HIGH)) {
      control_door(door_state);
      if (log_file != NULL) {
        if (door_state == 1) {
          log_event("Door opened.");
        } else {
          log_event("Door closed.");
        }
      }
    }

    delay(500); // Delay for stability
  }

  return 0;
}
