#include <stdio.h>
#include <pigpio.h>
#include <time.h>
#include <unistd.h>
#include <stdlib.h>

// Define constants
#define PCF8591_ADDR 0x48
#define PCF8591_BASE 200 // Virtual analog pin base
#define MOTOR_PIN 18       // GPIO pin connected to the motor control relay
#define THRESHOLD 500       // Threshold for sensor value
#define LOG_FILE "motor_log.txt"

int main() {
    int i2c_handle;
    int sensor_value;
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Exit with an error code
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, PCF8591_ADDR, 0); // Bus 1, address 0x48, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1; // Exit with an error code
    }

    // Set motor pin as output
    gpioSetMode(MOTOR_PIN, PI_OUTPUT);

    // Open log file
    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1; // Exit with an error code
    }

    // Main loop
    while (1) {
        // Read sensor value from virtual analog pin 0
        sensor_value = i2cReadByteData(i2c_handle, PCF8591_BASE + 0);
        if (sensor_value < 0) {
            fprintf(stderr, "Error reading sensor value!\n");
            fclose(fp);
            i2cClose(i2c_handle);
            gpioTerminate();
            return 1; // Exit with an error code
        }

        // Get current timestamp
        time(&rawtime);
        timeinfo = localtime(&rawtime);
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

        // Log sensor value and motor state to file
        fprintf(fp, "%s, Sensor Value: %d, Motor: %s\n", timestamp, sensor_value, gpioRead(MOTOR_PIN) ? "ON" : "OFF");
        fflush(fp); // Flush the buffer to ensure data is written immediately

        // Check if sensor value exceeds threshold
        if (sensor_value > THRESHOLD) {
            // Turn on motor
            gpioWrite(MOTOR_PIN, 1);
        } else {
            // Turn off motor
            gpioWrite(MOTOR_PIN, 0);
        }

        // Delay for a short period
        gpioDelay(100000); // 0.1 seconds
    }

    // Close I2C device and log file
    fclose(fp);
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

