#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <jansson.h>

// Constants
#define I2C_BUS "/dev/i2c-1"
#define SHT31_ADDR 0x44
#define MEASUREMENT_COMMAND 0x2C06
#define SCHEMA_FILE "schema.json"
#define LOG_FILE "environmental_log.json"
#define SAMPLE_INTERVAL_SEC 5
#define NUM_SAMPLES 10

// Global variables
static int i2c_fd = -1;
static FILE *log_file = NULL;
static volatile sig_atomic_t program_running = 1;

// Function prototypes
int i2c_open(const char *dev);
int i2c_write(int fd, int reg, const void *buf, int len);
int i2c_read(int fd, int reg, void *buf, int len);
int sht31_read_data(int fd, float *temperature, float *humidity);
int validate_data(float temperature, float humidity);
json_t *create_json_object(float temperature, float humidity);
json_t *create_json_array(int num_samples, float **temperatures, float **humidities);
int save_json_to_file(const char *filename, json_t *root);
int load_json_schema(const char *filename, json_t **schema);
int validate_json_against_schema(json_t *data, json_t *schema);
void signal_handler(int signal);

// I2C functions
int i2c_open(const char *dev) {
    int fd = open(dev, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C device");
        return -1;
    }
    return fd;
}

int i2c_write(int fd, int reg, const void *buf, int len) {
    if (write(fd, &reg, 1) != 1) {
        perror("Error writing to I2C device");
        return -1;
    }
    if (write(fd, buf, len) != len) {
        perror("Error writing data to I2C device");
        return -1;
    }
    return 0;
}

int i2c_read(int fd, int reg, void *buf, int len) {
    if (write(fd, &reg, 1) != 1) {
        perror("Error writing to I2C device for read");
        return -1;
    }
    if (read(fd, buf, len) != len) {
        perror("Error reading from I2C device");
        return -1;
    }
    return 0;
}

// SHT31-DIS functions
int sht31_read_data(int fd, float *temperature, float *humidity) {
    uint8_t write_data[2] = {MEASUREMENT_COMMAND >> 8, MEASUREMENT_COMMAND & 0xFF};
    uint8_t read_data[6];

    if (i2c_write(fd, 0x00, write_data, 2) < 0) {
        fprintf(stderr, "Error writing measurement command\n");
        return -1;
    }

    usleep(50000); // Wait for measurement (at least 15ms)

    if (i2c_read(fd, 0x00, read_data, 6) < 0) {
        fprintf(stderr, "Error reading data from SHT31-DIS\n");
        return -1;
    }

    // Convert data
    uint16_t temperature_raw = (read_data[0] << 8) | read_data[1];
    uint16_t humidity_raw = (read_data[3] << 8) | read_data[4];

    *temperature = -45.0 + (175.0 * (float)temperature_raw / 65535.0);
    *humidity = 100.0 * (float)humidity_raw / 65535.0;

    return 0;
}

// Validation functions
int validate_data(float temperature, float humidity) {
    if (temperature < -40.0 || temperature > 125.0) {
        fprintf(stderr, "Error: Temperature out of range: %.2f\n", temperature);
        return 0;
    }
    if (humidity < 0.0 || humidity > 100.0) {
        fprintf(stderr, "Error: Humidity out of range: %.2f\n", humidity);
        return 0;
    }
    return 1;
}

// JSON functions
json_t *create_json_object(float temperature, float humidity) {
    json_t *root = json_object();
    json_object_set_new(root, "timestamp", json_integer((long long)time(NULL)));
    json_object_set_new(root, "temperature", json_real(temperature));
    json_object_set_new(root, "humidity", json_real(humidity));
    return root;
}

json_t *create_json_array(int num_samples, float **temperatures, float **humidities) {
    json_t *root = json_array();
    for (int i = 0; i < num_samples; i++) {
        json_t *obj = create_json_object(temperatures[i][0], humidities[i][0]);
        json_array_append_new(root, obj);
    }
    return root;
}

int save_json_to_file(const char *filename, json_t *root) {
    int result = json_dump_file(root, filename, JSON_INDENT(4));
    if (result != 0) {
        fprintf(stderr, "Error saving JSON to file: %s\n", filename);
        return -1;
    }
    return 0;
}

int load_json_schema(const char *filename, json_t **schema) {
    *schema = json_load_file(filename, 0, NULL);
    if (!(*schema)) {
        fprintf(stderr, "Error loading JSON schema from file: %s\n", filename);
        return -1;
    }
    return 0;
}

int validate_json_against_schema(json_t *data, json_t *schema) {
    int result = json_validate(schema, data, &json_error_cb);
    if (result != 0) {
        fprintf(stderr, "JSON validation failed: %s\n", json_error_text(json_error_text(result)));
        return -1;
    }
    return 0;
}

// Signal handler
void signal_handler(int signal) {
    program_running = 0;
    fprintf(stderr, "Signal received, exiting...\n");
}

// Error handling
void handle_error(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Open I2C bus
    i2c_fd = i2c_open(I2C_BUS);
    if (i2c_fd < 0) {
        return 1;
    }

    // Set I2C slave address
    if (ioctl(i2c_fd, I2C_SLAVE, SHT31_ADDR) < 0) {
        perror("Error setting I2C slave address");
        close(i2c_fd);
        return 1;
    }

    // Load JSON schema
    json_t *json_schema = NULL;
    if (load_json_schema(SCHEMA_FILE, &json_schema) < 0) {
        close(i2c_fd);
        return 1;
    }

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (!log_file) {
        perror("Error opening log file");
        close(i2c_fd);
        json_decref(json_schema);
        return 1;
    }

    // Allocate memory for temperature and humidity readings
    float *temperatures = malloc(NUM_SAMPLES * sizeof(float));
    float *humidities = malloc(NUM_SAMPLES * sizeof(float));

    if (!temperatures || !humidities) {
        handle_error("Failed to allocate memory for sensor readings");
        fclose(log_file);
        close(i2c_fd);
        json_decref(json_schema);
        free(temperatures);
        free(humidities);
        return 1;
    }

    // Main loop
    while (program_running) {
        float temperature, humidity;

        // Read sensor data
        if (sht31_read_data(i2c_fd, &temperature, &humidity) < 0) {
            fprintf(stderr, "Error reading sensor data, retrying...\n");
            sleep(1); // Wait before retrying
            continue;
        }

        // Validate data
        if (!validate_data(temperature, humidity)) {
            fprintf(stderr, "Invalid sensor data, skipping...\n");
            sleep(1); // Wait before retrying
            continue;
        }

        // Store data
        temperatures[NUM_SAMPLES - 1] = temperature;
        humidities[NUM_SAMPLES - 1] = humidity;

        // Create JSON object
        json_t *json_object = create_json_object(temperature, humidity);

        // Validate JSON against schema
        if (validate_json_against_schema(json_object, json_schema) < 0) {
            fprintf(stderr, "JSON validation failed, skipping...\n");
        } else {
            // Save JSON to file
            if (save_json_to_file(LOG_FILE, json_object) < 0) {
                fprintf(stderr, "Error saving JSON to file, skipping...\n");
            }
        }

        json_decref(json_object);

        // Rotate data for circular buffer
        for (int i = 0; i < NUM_SAMPLES - 1; i++) {
            temperatures[i] = temperatures[i + 1];
            humidities[i] = humidities[i + 1];
        }

        // Sleep for the specified interval
        sleep(SAMPLE_INTERVAL_SEC);
    }

    // Cleanup
    fclose(log_file);
    close(i2c_fd);
    json_decref(json_schema);
    free(temperatures);
    free(humidities);

    return 0;
}

