// Function to send motion detection message to the server
void send_motion_alert(const char *timestamp) {
    struct sockaddr_in server_addr;
    char message[256];

    // Create socket
    socket_fd = socket(AF_INET, SOCK_DGRAM, 0);
    if (socket_fd < 0) {
        perror("Error creating socket");
        return;
    }

    // Configure server address
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(SERVER_PORT);
    if (inet_pton(AF_INET, SERVER_IP, &server_addr.sin_addr) <= 0) {
        perror("Invalid address/ Address not supported");
        close(socket_fd);
        return;
    }

    // Prepare message
    snprintf(message, sizeof(message), "Motion detected at: %s", timestamp);

    // Send message
    if (sendto(socket_fd, message, strlen(message), 0, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("Error sending message");
    }

    close(socket_fd);
}

