            } else if (!motion_detected) {
                last_motion_state = 0;
            }
        } else {
            fprintf(stderr, "Error: Invalid sensor reading: %d\n", motion_detected);
        }

        gpioDelay(100000); // Check every 100ms
    }

    // Cleanup
    printf("Cleaning up resources...\n");
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();

    return 0;
}

