/*
* Name: PiPIR.c
* Purpose: Detect motion using a HC-SR501 PIR sensor on GPIO 17, activate a GPIO 27-connected buzzer for 1 second upon detection, log timestamps to motion_log.txt, and display timestamps via console.
*/

#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <wiringPi.h>

// Function to detect motion using PIR sensor.
int detectMotion(int pi, int gpio, int buzzer, int *count) {
    if (gpioSetMode(gpio, PI_INPUT) < 0) {
        printf("Failed to set mode for GPIO %d\n", gpio);
        return -1;
    }
    int level = 0;
    if (gpioRead(gpio) == 0) {
        level = 1;
    }
    if (level != 0) {
        if (gpioWrite(buzzer, 1) < 0) {
            printf("Failed to write to GPIO %d\n", buzzer);
            return -1;
        }
        printf("Motion detected at %ld\n", time(NULL));
        if (gpioWrite(buzzer, 0) < 0) {
            printf("Failed to write to GPIO %d\n", buzzer);
            return -1;
        }
        (*count)++;
    }
    return 0;
}

int main(int argc, char *argv[]) {
    // Initialize pigpio.
    int pi = pigpio_start(NULL, NULL);
    if (pi < 0) {
        printf("Unable to connect to pigpio.\n");
        return -1;
    }
    // Initialize GPIO 17 for PIR sensor.
    if (gpioInitialise() < 0) {
        printf("Unable to initialize GPIO.\n");
        return -1;
    }
    // Set up GPIO 27 for buzzer.
    if (wiringPiSetup() < 0) {
        printf("Unable to initialize wiringPi.\n");
        return -1;
    }
    int gpio = 17;
    int buzzer = 27;
    int count = 0;
    while (1) {
        // Detect motion.
        detectMotion(pi, gpio, buzzer, &count);
        // Log timestamps.
        FILE *fptr;
        fptr = fopen("motion_log.txt", "a");
        fprintf(fptr, "%d, %ld\n", count, time(NULL));
        fclose(fptr);
        sleep(1);
    }
    // Stop pigpio.
    pigpio_stop(pi);
    return 0;
}
```

### Explanation:
- A function to detect motion and print the timestamps to the console is declared.
- Initialize pigpio and GPIO 17 for the PIR sensor.
- Initialize GPIO 27 for the buzzer.
- A variable is declared to count the number of motion detections.
- In a while loop, detect motion and log the timestamps.
- Stop pigpio.

### Build and Run:
- Compile the C program.
```bash
$ gcc -o PiPIR.exe PiPIR.c
```
- Run the program.
```bash
$ sudo ./PiPIR.exe
```
- To run the program every 30 seconds, use crontab.
```bash
$ crontab -e
```
- Append the following to crontab.
```bash
@reboot sudo /usr/local/bin/PiPIR.exe >> /home/pi/motion_log.txt 2>&1
```
- You can now reboot and check the motion_log.txt file.
```bash
$ cat motion_log.txt
```

