// Structure to hold sensor data
typedef struct {
    int gpio_pin;
    int sensor_id;
} sensor_data_t;

// Array of sensor data
sensor_data_t sensors[] = {
    {MOTION_SENSOR_1, 1},
    {MOTION_SENSOR_2, 2},
    {MOTION_SENSOR_3, 3}
};

int num_sensors = sizeof(sensors) / sizeof(sensors[0]);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    gpioTerminate(); // Release pigpio resources
    exit(0);
}

// Initializes the pigpio library and sets GPIO modes.
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Set GPIO pins as inputs for sensors and output for buzzer
    for (int i = 0; i < num_sensors; i++) {
        gpioSetMode(sensors[i].gpio_pin, PI_INPUT);
    }
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    return 0; // Indicate success
}

// Reads the state of a specified GPIO pin.
int read_sensor(int gpio_pin) {
    return gpioRead(gpio_pin);
}

// Activates the buzzer for a specified duration.
void activate_buzzer() {
    gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
    gpioDelay(BUZZER_DURATION * 1000000); // Delay for buzzer duration (microseconds)
    gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
}

// Logs motion detection event to a file.
void log_motion(int gpio_pin) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s - Motion detected on GPIO pin %d\n", timestamp, gpio_pin);
    fclose(fp);
}

int main() {
    // Install signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        for (int i = 0; i < num_sensors; i++) {
            int motion_detected = read_sensor(sensors[i].gpio_pin);
            if (motion_detected == 1) {
                printf("Motion detected on GPIO %d\n", sensors[i].gpio_pin);
                activate_buzzer();
                log_motion(sensors[i].gpio_pin);
                gpioDelay(500000); // Debounce delay (milliseconds)
            }
        }
        gpioDelay(100000); // Short delay to prevent busy-waiting (microseconds)
    }

    // Cleanup (should not reach here if signal handler works)
    gpioTerminate();
    return 0;
}
