#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <string.h>

// Define GPIO pins (wiringPi numbering)
#define MOTION_SENSOR_PIN 17
#define BUZZER_PIN 18

// Global variable for log file pointer
FILE *log_file = NULL;

// Flag to indicate if the interrupt is enabled
volatile int interruptEnabled = 1;

// Function prototypes
void motionDetected(void);
void triggerBuzzer(void);
void logMotion(void);
void cleanup(int signal);

int main(void) {
    // Initialize wiringPi using BCM GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Configure the motion sensor pin as an input
    pinMode(MOTION_SENSOR_PIN, INPUT);
    // Configure the buzzer pin as an output
    pinMode(BUZZER_PIN, OUTPUT);

    // Initialize buzzer to off state
    digitalWrite(BUZZER_PIN, LOW);

    // Set up interrupt on the motion sensor pin
    if (wiringPiISR(MOTION_SENSOR_PIN, INT_EDGE_RISING, motionDetected) < 0) {
        fprintf(stderr, "Error setting up ISR: %s\n", strerror(errno));
        return 1;
    }

    // Set up signal handler for clean exit
    signal(SIGINT, cleanup);

    printf("Home security system started. Press Ctrl+C to exit.\n");

    // Main loop (do nothing, everything is interrupt-driven)
    while (1) {
        delay(100); // Reduce CPU usage
    }

    return 0;
}

// Function to handle motion detection interrupt
void motionDetected(void) {
    if (interruptEnabled) {
        // Disable interrupt temporarily
        interruptEnabled = 0;

        triggerBuzzer();
        logMotion();

        delay(500); // Debounce delay

        // Re-enable the interrupt
        interruptEnabled = 1;
    }
}

// Function to trigger the buzzer
void triggerBuzzer(void) {
    digitalWrite(BUZZER_PIN, HIGH); // Turn buzzer on
    delay(1000);                     // Keep buzzer on for 1 second
    digitalWrite(BUZZER_PIN, LOW);  // Turn buzzer off
}

// Function to log motion detection event
void logMotion(void) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    // Get current time
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    // Format the timestamp
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Open the log file in append mode
    log_file = fopen("motion_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        // Continue without logging, but indicate an error occurred.
        return;
    }

    // Write log entry
    fprintf(log_file, "Motion detected at: %s\n", timestamp);

    // Close the log file
    fclose(log_file);
}

// Function to handle signals and clean up resources
void cleanup(int signal) {
    printf("\nCleaning up and exiting...\n");

    // Turn off the buzzer
    digitalWrite(BUZZER_PIN, LOW);

    // Close the log file if it's open
    if (log_file != NULL) {
        fclose(log_file);
    }

    exit(0);
}

