#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <time.h>
#include <signal.h>

// Define GPIO pins
#define PIR_SENSOR_PIN 17
#define BUZZER_PIN 18

// Function prototypes
int readPIRSensor();
void activateBuzzer();
void logMotionEvent();
void signalHandler(int signal);

// Global variable to indicate program termination
volatile sig_atomic_t programRunning = 1;

// Signal handler function
void signalHandler(int signal) {
    programRunning = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    // Deactivate buzzer
    digitalWrite(BUZZER_PIN, LOW);
    exit(0);
}

// Function to read the PIR sensor
int readPIRSensor() {
    return digitalRead(PIR_SENSOR_PIN);
}

// Function to activate the buzzer
void activateBuzzer() {
    digitalWrite(BUZZER_PIN, HIGH);
    delay(1000); // Buzzer on for 1 second
    digitalWrite(BUZZER_PIN, LOW);
}

// Function to log motion events
void logMotionEvent() {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fp = fopen("motion_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening motion_log.txt");
        return;
    }

    fprintf(fp, "%s - Motion detected!\n", timestamp);
    fclose(fp);
}

int main() {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, signalHandler);

    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi!\n");
        return 1;
    }

    // Set PIR sensor pin as input
    pinMode(PIR_SENSOR_PIN, INPUT);

    // Set buzzer pin as output
    pinMode(BUZZER_PIN, OUTPUT);

    // Register interrupt handler for PIR sensor
    if (wiringPiISR(PIR_SENSOR_PIN, INT_EDGE_RISING, activateBuzzer) < 0) {
        fprintf(stderr, "Error setting up interrupt!\n");
        return 1;
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (programRunning) {
