// Define GPIO pins
#define PIR_SENSOR_PIN 17
#define LED_PIN 27

// Define constants
#define BLINK_DURATION 5  // seconds
#define BLINK_ON_TIME 500 // milliseconds
#define BLINK_OFF_TIME 500 // milliseconds
#define DEBOUNCE_DELAY 200 // milliseconds

// Global variable for signal handling
volatile sig_atomic_t program_running = 1;

// Signal handler function
void signal_handler(int signal) {
    fprintf(stderr, "\nCaught signal %d, exiting gracefully...\n", signal);
    program_running = 0;
}

// Function to initialize GPIO
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Set PIR sensor pin as input
    if (gpioSetMode(PIR_SENSOR_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set PIR sensor pin as input\n");
        gpioTerminate();
        return 1;
    }

    // Set LED pin as output
    if (gpioSetMode(LED_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Failed to set LED pin as output\n");
        gpioTerminate();
        return 1;
    }

    return 0; // Indicate success
}

// Function to detect motion with debounce
int detect_motion() {
    static int last_state = 0;
    static unsigned long last_time = 0;
    int current_state = gpioRead(PIR_SENSOR_PIN);
    unsigned long current_time = gpioTick();

    if (current_state != last_state) {
        if (current_time - last_time > DEBOUNCE_DELAY * 1000) { // Convert ms to microseconds
            last_state = current_state;
            last_time = current_time;
            if (current_state == 1) {
                return 1; // Motion detected
            }
        }
    }
    return 0; // No motion detected
}

// Function to blink the LED
void blink_led(int duration, int on_time, int off_time) {
    unsigned long start_time = gpioTick();
    while ((gpioTick() - start_time) < (duration * 1000000) && program_running) { // Convert seconds to microseconds
        gpioWrite(LED_PIN, 1); // Turn LED on
        gpioDelay(on_time);     // Wait for on_time milliseconds
        gpioWrite(LED_PIN, 0); // Turn LED off
        gpioDelay(off_time);    // Wait for off_time milliseconds
    }
}

// Function to log motion to a file
int log_motion() {
    FILE *fp = fopen("motion_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening motion_log.txt for writing\n");
        return 1; // Indicate failure
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];

    if (strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm) == 0) {
        fprintf(stderr, "Error formatting timestamp\n");
        fclose(fp);
        return 1; // Indicate failure
    }

    fprintf(fp, "%s - Motion Detected\n", timestamp);
    if (ferror(fp)) {
        fprintf(stderr, "Error writing to file\n");
        fclose(fp);
        return 1; // Indicate failure
    }

    fclose(fp);
    return 0; // Indicate success
}

// Function to cleanup GPIO
void cleanup_gpio() {
    gpioWrite(LED_PIN, 0); // Turn off the LED
    gpioTerminate();
}

int main() {
    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    fprintf(stderr, "Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        if (detect_motion()) {
            fprintf(stderr, "Motion detected!\n");
            if (log_motion() != 0) {
                fprintf(stderr, "Failed to log motion\n");
            }
            blink_led(BLINK_DURATION, BLINK_ON_TIME, BLINK_OFF_TIME);
        }
        gpioDelay(100); // Check for motion every 100ms
    }

    // Cleanup GPIO before exiting
    cleanup_gpio();
    fprintf(stderr, "Exiting.\n");
    return 0;
}

