#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define constants
#define PIR_GPIO 17
#define VL53L1X_ADDRESS 0x29
#define DISTANCE_REG 0x0089 // Example register for distance.  Check datasheet.
#define CONFIG_REG 0x002D // Example config register. Check datasheet.
#define TIMEOUT_RETRIES 3 // Number of retries for I2C communication

// Global variables (minimize usage)
static volatile int running = 1;
static int i2c_handle;

// Function prototypes
int isMotionDetected();
int readDistance();
void logData(char *timestamp, int distance);
void signalHandler(int signum);
int initializeVL53L1X();

// Signal handler for graceful termination
void signalHandler(int signum) {
    running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signum);
}

// Checks for motion detected by the PIR sensor
int isMotionDetected() {
    // Debounce the PIR sensor by reading it multiple times with a short delay
    int count = 0;
    for (int i = 0; i < 5; i++) {
        if (gpioRead(PIR_GPIO) == 1) {
            count++;
        }
        gpioDelay(1); // 1 ms delay
    }
    return (count >= 3) ? 1 : 0; // Consider motion detected if high for majority of readings
}

// Reads the distance from the VL53L1X sensor
int readDistance() {
    char write_buffer[3];
    char read_buffer[2];
    int distance = -1; // Default to error value
    int retries = TIMEOUT_RETRIES;

    // Example: Write to configuration register (check datasheet for correct values)
    write_buffer[0] = CONFIG_REG >> 8; // MSB of register address
    write_buffer[1] = CONFIG_REG & 0xFF; // LSB of register address
    write_buffer[2] = 0x01; // Example config value

    while (retries > 0) {
        if (i2cWriteDevice(i2c_handle, write_buffer, 3) == 3) {
            break; // Success
        } else {
            fprintf(stderr, "Error: I2C write to config register failed, retrying...\n");
            gpioDelay(10); // Wait before retrying
            retries--;
        }
    }

    if (retries == 0) {
        fprintf(stderr, "Error: I2C write to config register failed after multiple retries.\n");
        return -1;
    }

    gpioDelay(1); // Delay after writing

    // Read distance register
    write_buffer[0] = DISTANCE_REG >> 8; // MSB of register address
    write_buffer[1] = DISTANCE_REG & 0xFF; // LSB of register address

    retries = TIMEOUT_RETRIES;
    while (retries > 0) {
        if (i2cWriteDevice(i2c_handle, write_buffer, 2) == 2) {
            break; // Success
        } else {
            fprintf(stderr, "Error: I2C write to distance register failed, retrying...\n");
            gpioDelay(10); // Wait before retrying
            retries--;
        }
    }

    if (retries == 0) {
        fprintf(stderr, "Error: I2C write to distance register failed after multiple retries.\n");
        return -1;
    }

    gpioDelay(1); // Delay after writing address

    retries = TIMEOUT_RETRIES;
    while (retries > 0) {
        if (i2cReadDevice(i2c_handle, read_buffer, 2) == 2) {
            // Combine the two bytes to form the distance
            distance = (read_buffer[0] << 8) | read_buffer[1];
            break; // Success
        } else {
            fprintf(stderr, "Error: I2C read failed, retrying...\n");
            gpioDelay(10); // Wait before retrying
            retries--;
        }
    }

    if (retries == 0) {
        fprintf(stderr, "Error: I2C read failed after multiple retries.\n");
        return -1;
    }

    return distance;
}

