static int i2c_handle_2 = -1;
static int i2c_handle_3 = -1;
static FILE *log_file = NULL;
static volatile int running = 1;

// Structure to hold calibration data
typedef struct {
    int AC1;
    int AC2;
    int AC3;
    unsigned int AC4;
    unsigned int AC5;
    unsigned int AC6;
    int B1;
    int B2;
    int MB;
    int MC;
    int MD;
} bmp180_calibration_data;

// Function to read calibration data from BMP180
int get_calibration_data(int i2c_handle, bmp180_calibration_data *cal_data) {
    char buf[22];
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_CAL_START, buf, 22) != 22) {
        fprintf(stderr, "Error reading calibration data\n");
        return -1;
    }

    cal_data->AC1 = (buf[0] << 8) | buf[1];
    cal_data->AC2 = (buf[2] << 8) | buf[3];
    cal_data->AC3 = (buf[4] << 8) | buf[5];
    cal_data->AC4 = (buf[6] << 8) | buf[7];
    cal_data->AC5 = (buf[8] << 8) | buf[9];
    cal_data->AC6 = (buf[10] << 8) | buf[11];
    cal_data->B1 = (buf[12] << 8) | buf[13];
    cal_data->B2 = (buf[14] << 8) | buf[15];
    cal_data->MB = (buf[16] << 8) | buf[17];
    cal_data->MC = (buf[18] << 8) | buf[19];
    cal_data->MD = (buf[20] << 8) | buf[21];

    return 0;
}

// Function to read pressure from BMP180 sensor
int read_bmp180(int i2c_handle, float *pressure, bmp180_calibration_data cal_data) {
    char buf[3];
    int ut, up;
    long x1, x2, x3, b3, b5, b6, p;
    unsigned long b4, b7;

    // Request temperature reading
    if (i2cWriteByteData(i2c_handle, BMP180_REG_CONTROL, 0x2E) != 0) {
        fprintf(stderr, "Error writing to control register (temp)\n");
        return -1;
    }
    time_sleep(0.005); // Wait 4.5ms

    // Read uncompensated temperature (UT)
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_MSB, buf, 2) != 2) {
        fprintf(stderr, "Error reading temperature data\n");
        return -1;
    }
    ut = (buf[0] << 8) + buf[1];

    // Request pressure reading
    if (i2cWriteByteData(i2c_handle, BMP180_REG_CONTROL, 0x34 + (OSS << 6)) != 0) {
        fprintf(stderr, "Error writing to control register (pressure)\n");
        return -1;
    }
    time_sleep(0.008); // Wait 7.5ms (OSS = 0)

    // Read uncompensated pressure (UP)
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_MSB, buf, 3) != 3) {
        fprintf(stderr, "Error reading pressure data\n");
        return -1;
    }
    up = ((unsigned long) buf[0] << 16 | (unsigned long) buf[1] << 8 | (unsigned long) buf[2]) >> (8 - OSS);


    // Calculate temperature
    x1 = ((long)ut - (long)cal_data.AC6) * ((long)cal_data.AC5) / pow(2, 15);
    x2 = ((long)cal_data.MC * pow(2, 11)) / (x1 + (long)cal_data.MD);
    long b5_calc = x1 + x2;

    // Calculate pressure
    b6 = b5_calc - 4000;
    x1 = (cal_data.B2 * (b6 * b6 / pow(2, 12))) / pow(2, 11);
    x2 = cal_data.AC2 * b6 / pow(2, 11);
    x3 = x1 + x2;
    b3 = (((cal_data.AC1 * 4 + x3) << OSS) + 2) / 4;

    x1 = cal_data.AC3 * b6 / pow(2, 13);
    x2 = (cal_data.B1 * (b6 * b6 / pow(2, 12))) / pow(2, 16);
    x3 = ((x1 + x2) + 2) / 4;
    b4 = cal_data.AC4 * (unsigned long)(x3 + 32768) / pow(2, 15);
    b7 = ((unsigned long)up - b3) * (50000 >> OSS);

    if (b7 < 0x80000000) {
        p = (b7 * 2) / b4;
    } else {
        p = (b7 / b4) * 2;
    }

    x1 = (p / pow(2, 8)) * (p / pow(2, 8));
    x1 = (x1 * 3038) / pow(2, 16);
    x2 = (-7357 * p) / pow(2, 16);

    *pressure = p + (x1 + x2 + 3791) / pow(2, 4);

    return 0;
}

// Function to log pressure data to file
void log_pressure(float pressure, int sensor_id) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d, Sensor %d: %.2f Pa\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, sensor_id, pressure);
    fflush(log_file); // Ensure data is written to disk immediately
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = 0;
    gpioWrite(LED_PIN, 0); // Turn off LED
    if (i2c_handle_1 >= 0) i2cClose(i2c_handle_1);
    if (i2c_handle_2 >= 0) i2cClose(i2c_handle_2);
    if (i2c_handle_3 >= 0) i2cClose(i2c_handle_3);
    if (log_file != NULL) fclose(log_file);
    gpioTerminate();
    exit(0);
}

