    i2c_handle_1 = i2cOpen(1, BMP180_ADDR_1, 0);
    i2c_handle_2 = i2cOpen(1, BMP180_ADDR_2, 0);
    i2c_handle_3 = i2cOpen(1, BMP180_ADDR_3, 0);

    if (i2c_handle_1 < 0 || i2c_handle_2 < 0 || i2c_handle_3 < 0) {
        fprintf(stderr, "Error opening I2C bus\n");
        if (i2c_handle_1 >= 0) i2cClose(i2c_handle_1);
        if (i2c_handle_2 >= 0) i2cClose(i2c_handle_2);
        if (i2c_handle_3 >= 0) i2cClose(i2c_handle_3);
        gpioTerminate();
        return 1;
    }

    // Read calibration data for each sensor
    if (get_calibration_data(i2c_handle_1, &cal_data_1) != 0 ||
        get_calibration_data(i2c_handle_2, &cal_data_2) != 0 ||
        get_calibration_data(i2c_handle_3, &cal_data_3) != 0) {
        fprintf(stderr, "Error reading calibration data from sensors\n");
        i2cClose(i2c_handle_1);
        i2cClose(i2c_handle_2);
        i2cClose(i2c_handle_3);
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen("pressure_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file\n");
        i2cClose(i2c_handle_1);
        i2cClose(i2c_handle_2);
        i2cClose(i2c_handle_3);
        gpioTerminate();
        return 1;
    }

    // Set LED pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (running) {
