int initialize_pigpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Function to cleanup pigpio
void cleanup_pigpio() {
    gpioTerminate();
}

// Function to read the rain sensor
int read_rain_sensor() {
    return gpioRead(RAIN_SENSOR_PIN);
}

// Function to control the DC motor
void control_motor(int direction, int speed) {
    gpioWrite(MOTOR_DIRECTION_PIN, direction);
    gpioPWM(MOTOR_PWM_PIN, speed);
}

// Function to log events to a file
void log_event(const char *event) {
    FILE *fp = fopen("window_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s: %s\n", timestamp, event);
    fclose(fp);
}

