void open_window() {
    printf("Opening window...\n");
    control_motor(MOTOR_FORWARD, MOTOR_SPEED);
    log_event("Window opened");
    gpioDelay(5000000); // 5 seconds
    control_motor(0, 0); // Stop the motor
}

// Function to close the window
void close_window() {
    printf("Closing window...\n");
    control_motor(MOTOR_BACKWARD, MOTOR_SPEED);
    log_event("Window closed");
    gpioDelay(5000000); // 5 seconds
    control_motor(0, 0); // Stop the motor
}

