// Define GPIO pins for locks and sensors
#define LOCK_1_PIN 17
#define LOCK_2_PIN 27
#define SENSOR_1_PIN 22
#define SENSOR_2_PIN 23

// Define the duration for which the locks will be open (in seconds)
#define LOCK_OPEN_DURATION 5

// Log file path
#define LOG_FILE "/var/log/lock_events.log"

// Function prototypes
int gpio_initialization();
void lock_open(int lock_pin, int duration_seconds);
void lock_close(int lock_pin);
int sensor_read(int sensor_pin);
void log_event(const char* event_string);
void signal_handler(int signal);

// Global variable to track program state for graceful shutdown
volatile sig_atomic_t program_running = 1;

int main() {
    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize the pigpio library and GPIO pins
    if (gpio_initialization() != 0) {
        fprintf(stderr, "GPIO initialization failed. Check log file for details.\n");
        return 1;
    }

    log_event("Access control system started.");

    // Main loop for monitoring sensors and controlling locks
    while (program_running) {
        // Read the state of the sensors
        int sensor1_value = sensor_read(SENSOR_1_PIN);
        int sensor2_value = sensor_read(SENSOR_2_PIN);

        // Check if both sensors are HIGH (indicating authorization)
        if (sensor1_value == 1 && sensor2_value == 1) {
            log_event("Authorization signal detected. Opening locks.");
            lock_open(LOCK_1_PIN, LOCK_OPEN_DURATION);
            lock_open(LOCK_2_PIN, LOCK_OPEN_DURATION);
            // Small delay to prevent rapid re-triggering
            sleep(LOCK_OPEN_DURATION + 1); // Wait longer than lock open duration
        } else {
          //Small delay for the main loop
          gpioDelay(1000); //check every 1000 microseconds or 1 millisecond
        }
    }

    // Clean up and exit
    log_event("Access control system shutting down.");
    lock_close(LOCK_1_PIN);
    lock_close(LOCK_2_PIN);
    gpioTerminate();
    return 0;
}

// Function to initialize the pigpio library and GPIO pins
int gpio_initialization() {
    if (gpioInitialise() < 0) {
        log_event("pigpio initialisation failed");
        return 1;
    }

    // Set GPIO pins for locks as outputs
    gpioSetMode(LOCK_1_PIN, PI_OUTPUT);
    gpioSetMode(LOCK_2_PIN, PI_OUTPUT);

    // Set GPIO pins for sensors as inputs with pull-down resistors
    gpioSetMode(SENSOR_1_PIN, PI_INPUT);
    gpioSetPullUpDown(SENSOR_1_PIN, PI_PUD_DOWN); // Use pull-down resistor
    gpioSetMode(SENSOR_2_PIN, PI_INPUT);
    gpioSetPullUpDown(SENSOR_2_PIN, PI_PUD_DOWN); // Use pull-down resistor

    return 0;
}

// Function to open a specified lock for a given duration
void lock_open(int lock_pin, int duration_seconds) {
    char event_string[100];
    snprintf(event_string, sizeof(event_string), "Opening lock on pin %d for %d seconds.", lock_pin, duration_seconds);
    log_event(event_string);

    gpioWrite(lock_pin, 1); // Activate the lock (HIGH)
    gpioDelay(duration_seconds * 1000000); // Delay for the specified duration (microseconds)
    lock_close(lock_pin);
}

// Function to close a specified lock
void lock_close(int lock_pin) {
    char event_string[50];
    snprintf(event_string, sizeof(event_string), "Closing lock on pin %d.", lock_pin);
    log_event(event_string);

    gpioWrite(lock_pin, 0); // Deactivate the lock (LOW)
}

// Function to read the state of a digital input sensor
int sensor_read(int sensor_pin) {
    int sensor_value = gpioRead(sensor_pin);
    char event_string[50];
    snprintf(event_string, sizeof(event_string), "Sensor on pin %d read value: %d", sensor_pin, sensor_value);
    //log_event(event_string); //commenting out to avoid log spam
    return sensor_value;
}

// Function to log an event to the log file with a timestamp
void log_event(const char* event_string) {
    FILE *log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "[%s] %s\n", timestamp, event_string);
    fclose(log_file);
    printf("[%s] %s\n", timestamp, event_string); // Also print to console
}

// Signal handler function for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    char event_string[50];
    snprintf(event_string, sizeof(event_string), "Received signal %d. Shutting down...",(int)signal);
    log_event(event_string);
}

