// Function to initialize a GPIO pin
int init_gpio(int pin) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi on pin %d\n", pin);
        return -1;
    }

    pinMode(pin, OUTPUT);
    digitalWrite(pin, LOW); // Initialize to unlocked state
    current_lock_state = 0;
    return 0;
}

// Function to set the lock state
int set_lock_state(int pin, int state) {
    if (state != 0 && state != 1) {
        fprintf(stderr, "Invalid lock state: %d\n", state);
        return -1;
    }

    digitalWrite(pin, state);
    current_lock_state = state;
    return 0;
}

// Function to log an event to the log file
int log_event(const char *message) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return -1;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "[%s] %s\n", timestamp, message);
    fclose(fp);
    return 0;
}

// Timer callback function
void timer_callback(void *userdata) {
    timer_config_t *config = (timer_config_t *)userdata;
    int lock_number = config->lock_number;
    int state = config->state;

    char log_message[128];
    snprintf(log_message, sizeof(log_message), "Lock %d %s", lock_number, (state == 1) ? "opened" : "closed");
    log_event(log_message);

    if (set_lock_state(lock_number == 1 ? LOCK_1_PIN : LOCK_2_PIN, state) != 0) {
        fprintf(stderr, "Error setting lock state for lock %d\n", lock_number);
        log_event("Error setting lock state");
    }
}

// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);

    // Close all locks before exiting
    set_lock_state(LOCK_1_PIN, 0);
    set_lock_state(LOCK_2_PIN, 0);

    exit(0);
}

