        fprintf(stderr, "Error initializing LOCK_2_PIN\n");
        return 1;
    }

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Timer configuration
    struct timespec lock_open_time = {3, 0}; // 3 seconds
    struct timespec lock_close_time = {2, 0}; // 2 seconds

    timer_config_t lock_1_open_config = {1, 1};
    timer_config_t lock_1_close_config = {1, 0};
    timer_config_t lock_2_open_config = {2, 1};
    timer_config_t lock_2_close_config = {2, 0};

    // Main loop
    while (1) {
        // Open lock 1 for 3 seconds
        timer_callback(&lock_1_open_config);
        delay(lock_open_time.tv_sec * 1000 + lock_open_time.tv_nsec / 1000000);

        // Close lock 1 for 2 seconds
        timer_callback(&lock_1_close_config);
        delay(lock_close_time.tv_sec * 1000 + lock_close_time.tv_nsec / 1000000);

        // Open lock 2 for 3 seconds
        timer_callback(&lock_2_open_config);
        delay(lock_open_time.tv_sec * 1000 + lock_open_time.tv_nsec / 1000000);

        // Close lock 2 for 2 seconds
        timer_callback(&lock_2_close_config);
        delay(lock_close_time.tv_sec * 1000 + lock_close_time.tv_nsec / 1000000);
    }

    return 0;
}
