#define ECHO_PIN 18
#define BUZZER_PIN 27

// Define constants
#define SOUND_SPEED 34300.0 // Speed of sound in cm/s
#define MAX_DISTANCE 400.0  // Maximum measurable distance in cm
#define MIN_DISTANCE 0.0    // Minimum measurable distance in cm
#define TIMEOUT 25000       // Timeout for ultrasonic sensor in us

// Define proximity zones
#define PROXIMITY_ZONE_1 20.0
#define PROXIMITY_ZONE_2 50.0

// Define melody frequencies (Hz)
// Zone 1: Short, low tones
float melody_zone1[] = {200, 250, 300};

// Zone 2: Medium tones
float melody_zone2[] = {400, 450, 500, 550};

// Zone 3: High tones
float melody_zone3[] = {800, 850, 900, 950};

// Function prototypes
void signal_handler(int signal);
void triggerSensor();
double getDistance();
void playMelody(float frequencies[], int numFrequencies);
void volumeControl(int volume);
void errorHandler(const char *message);

// Global variable for graceful shutdown
volatile sig_atomic_t program_running = 1;

int main(int argc, char *argv[]) {
    int volume;

    // Parse command-line arguments for volume control
    if (argc > 1) {
        volume = atoi(argv[1]);
        if (volume < 0 || volume > 100) {
            fprintf(stderr, "Error: Volume must be between 0 and 100.\n");
            return 1;
        }
    } else {
        volume = 50; // Default volume
    }

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed.\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Doorbell running. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        double distance = getDistance();

        if (distance > 0) {
            printf("Distance: %.2f cm\n", distance);

            // Determine proximity zone
            if (distance < PROXIMITY_ZONE_1) {
                printf("Zone 1\n");
                playMelody(melody_zone1, sizeof(melody_zone1) / sizeof(melody_zone1[0]));
            } else if (distance < PROXIMITY_ZONE_2) {
                printf("Zone 2\n");
                playMelody(melody_zone2, sizeof(melody_zone2) / sizeof(melody_zone2[0]));
            } else {
                printf("Zone 3\n");
                playMelody(melody_zone3, sizeof(melody_zone3) / sizeof(melody_zone3[0]));
            }
        } else {
            errorHandler("Error: Invalid distance reading.");
        }

        gpioDelay(100); // Delay between distance readings
    }

    // Cleanup
    gpioTerminate();
    printf("Doorbell stopped.\n");

    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, stopping...\n", signal);
    program_running = 0;
}

// Function to trigger the ultrasonic sensor
void triggerSensor() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);
}

// Function to measure the distance using the ultrasonic sensor
double getDistance() {
    long long startTime, endTime, pulseDuration;
    double distance;

    // Trigger the sensor
    triggerSensor();

    // Measure the echo pulse duration
    startTime = gpioTick();
    while (gpioRead(ECHO_PIN) == 0) {
        if (gpioTick() - startTime > TIMEOUT) {
            errorHandler("Timeout waiting for echo start.");
            return -1; // Timeout
        }
    }
    startTime = gpioTick();

    endTime = gpioTick();
    while (gpioRead(ECHO_PIN) == 1) {
        if (gpioTick() - endTime > TIMEOUT) {
            errorHandler("Timeout waiting for echo end.");
            return -1; // Timeout
        }
    }
    endTime = gpioTick();

    pulseDuration = endTime - startTime;

    // Calculate distance
    distance = (double)pulseDuration * SOUND_SPEED / 2000000.0; // in cm

    // Validate distance
    if (distance < MIN_DISTANCE || distance > MAX_DISTANCE) {
        errorHandler("Invalid distance reading.");
        return -1; // Invalid reading
    }

    return distance;
}

// Function to play a melody on the buzzer
void playMelody(float frequencies[], int numFrequencies) {
    int i;
    for (i = 0; i < numFrequencies; i++) {
        gpioSetPWMfrequency(BUZZER_PIN, frequencies[i]);
        gpioPWM(BUZZER_PIN, 128); // 50% duty cycle (0-255)
        gpioDelay(200); // Delay between notes
    }
    gpioPWM(BUZZER_PIN, 0); // Stop the buzzer
}

// Function to handle errors
void errorHandler(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    gpioPWM(BUZZER_PIN, 0); // Ensure buzzer is off
}

// Function to control the volume using PWM
void volumeControl(int volume) {
    if (volume >= 0 && volume <= 100) {
        int pwm_value = volume * 2.55; // Map volume (0-100) to PWM (0-255)
        gpioPWM(BUZZER_PIN, pwm_value); // Set PWM duty cycle
    } else {
        fprintf(stderr, "Error: Volume must be between 0 and 100.\n");
    }
}
