#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pigpio.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>

#define OLED_SPI_CHANNEL 0
#define OLED_SPI_SPEED 1000000
#define OLED_SPI_MODE 0
#define OLED_DC_PIN 24
#define OLED_RST_PIN 25
#define OLED_CS_PIN 23

#define OLED_I2C_ADDRESS 0x3C

#define OLED_WIDTH 128
#define OLED_HEIGHT 64
#define OLED_BYTES_PER_PIXEL 2
#define OLED_BUFFER_SIZE (OLED_WIDTH * OLED_HEIGHT * OLED_BYTES_PER_PIXEL)

#define OLED_INIT_DELAY 10000

uint16_t oled_buffer[OLED_BUFFER_SIZE];

void oled_init() {
    memset(oled_buffer, 0, OLED_BUFFER_SIZE);

    wiringPiSPISetup(OLED_SPI_CHANNEL, OLED_SPI_SPEED);
    wiringPiSPISetupMode(OLED_SPI_CHANNEL, OLED_SPI_MODE);

    pinMode(OLED_CS_PIN, OUTPUT);
    pinMode(OLED_DC_PIN, OUTPUT);
    pinMode(OLED_RST_PIN, OUTPUT);
    digitalWrite(OLED_CS_PIN, HIGH);
    digitalWrite(OLED_DC_PIN, HIGH);
    digitalWrite(OLED_RST_PIN, HIGH);
    delay(OLED_INIT_DELAY);
    digitalWrite(OLED_RST_PIN, LOW);
    delay(10);
    digitalWrite(OLED_RST_PIN, HIGH);
    digitalWrite(OLED_DC_PIN, LOW);
    digitalWrite(OLED_CS_PIN, LOW);
}

void oled_command(uint8_t cmd) {
    digitalWrite(OLED_DC_PIN, LOW);
    digitalWrite(OLED_CS_PIN, LOW);
    wiringPiSPIDataRW(OLED_SPI_CHANNEL, &cmd, 1);
    digitalWrite(OLED_CS_PIN, HIGH);
}

void oled_data(uint8_t *data, uint32_t length) {
    digitalWrite(OLED_DC_PIN, HIGH);
    digitalWrite(OLED_CS_PIN, LOW);
    wiringPiSPIDataRW(OLED_SPI_CHANNEL, data, length);
    digitalWrite(OLED_CS_PIN, HIGH);
}

void oled_draw_pixel(uint8_t x, uint8_t y, uint16_t color) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    uint16_t index = (y * OLED_WIDTH) + x;
    oled_buffer[index] = color;
}

void oled_draw_line(uint8_t x0, uint8_t y0, uint8_t x1, uint8_t y1, uint16_t color) {
    if(x0 >= OLED_WIDTH || y0 >= OLED_HEIGHT)
        return;

    if(x1 >= OLED_WIDTH || y1 >= OLED_HEIGHT)
        return;

    int x, y, dx, dy, err, e2;

    dx = x1 - x0;
    dy = y1 - y0;
    x = x0;
    y = y0;

    if (dy < 0)
        dy = -dy;
    if (dx < 0)
        dx = -dx;
    err = (dx > dy ? dx : -dy) / 2;
    e2 = err;

    while(x != x1 || y != y1) {
        oled_draw_pixel(x, y, color);

        if (e2 > -dx) {
            err -= dy;
            e2 += dx;
        }
        else {
            err += dx;
            e2 -= dy;
        }

        if (x > x1)
            x--;
        if (y > y1)
            y--;
        if (x < x1)
            x++;
        if (y < y1)
            y++;
    }

    oled_draw_pixel(x1, y1, color);
}

void oled_draw_horizontal_line(uint8_t x, uint8_t y, uint8_t length, uint16_t color) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    if(x + length > OLED_WIDTH)
        return;

    for(uint8_t i = 0; i < length; ++i) {
        oled_draw_pixel(x + i, y, color);
    }
}

void oled_draw_vertical_line(uint8_t x, uint8_t y, uint8_t length, uint16_t color) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    if(y + length > OLED_HEIGHT)
        return;

    for(uint8_t i = 0; i < length; ++i) {
        oled_draw_pixel(x, y + i, color);
    }
}

void oled_draw_rectangle(uint8_t x, uint8_t y, uint8_t w, uint8_t h, uint16_t color) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    if(x + w > OLED_WIDTH)
        return;

    if(y + h > OLED_HEIGHT)
        return;

    oled_draw_horizontal_line(x, y, w, color);
    oled_draw_horizontal_line(x, y + h - 1, w, color);
    oled_draw_vertical_line(x, y, h, color);
    oled_draw_vertical_line(x + w - 1, y, h, color);
}

void oled_draw_circle(uint8_t x, uint8_t y, uint8_t radius, uint16_t color) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    int16_t f = 1 - radius;
    int16_t ddF_x = 1;
    int16_t ddF_y = -2 * radius;
    int16_t x1 = 0;
    int16_t y1 = radius;

    oled_draw_pixel(x, y + radius, color);
    oled_draw_pixel(x, y - radius, color);
    oled_draw_pixel(x + radius, y, color);
    oled_draw_pixel(x - radius, y, color);

    while (x1 < y1) {
        if (f >= 0) {
            y1--;
            ddF_y += 2;
            f += ddF_y;
        }
        x1++;
        ddF_x += 2;
        f += ddF_x;

        oled_draw_pixel(x + x1, y + y1, color);
        oled_draw_pixel(x - x1, y + y1, color);
        oled_draw_pixel(x + x1, y - y1, color);
        oled_draw_pixel(x - x1, y - y1, color);
        oled_draw_pixel(x + y1, y + x1, color);
        oled_draw_pixel(x - y1, y + x1, color);
        oled_draw_pixel(x + y1, y - x1, color);
        oled_draw_pixel(x - y1, y - x1, color);
    }
}

void oled_draw_char(uint8_t x, uint8_t y, char c, uint8_t size, uint16_t color) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    if(x + 6 * size > OLED_WIDTH)
        return;

    if(y + 8 * size > OLED_HEIGHT)
        return;

    uint8_t line;
    uint8_t dots;
    uint8_t mask;

    for(uint8_t i = 0; i < 8; ++i) {
        line = 0;
        if(i == 7)
            line = 0x0;
        else {
            line = font[(c - 0x20) * 8 + i];
        }

        for(uint8_t j = 0; j < 8; ++j) {
            dots = 0;
            mask = 0x1 << (7 - j);
            if((line & mask) == mask)
                dots = 1;

            for(uint8_t k = 0; k < size; ++k) {
                for(uint8_t l = 0; l < size; ++l) {
                    oled_draw_pixel(x + (j * size) + k, y + (i * size) + l, color * dots);
                }
            }
        }
    }
}

void oled_draw_string(uint8_t x, uint8_t y, char *str, uint8_t size, uint16_t color) {
    while(*str) {
        oled_draw_char(x, y, *str, size, color);
        x += 6 * size;
        str++;
    }
}

void oled_draw_image(uint8_t x, uint8_t y, uint8_t w, uint8_t h, uint8_t *data) {
    if(x >= OLED_WIDTH || y >= OLED_HEIGHT)
        return;

    if(x + w > OLED_WIDTH)
        return;

    if(y + h > OLED_HEIGHT)
        return;

    for(uint16_t i = 0; i < (w * h * OLED_BYTES_PER_PIXEL); i += 2) {
        uint8_t r = data[i + 0];
        uint8_t g = data[i + 1];
        uint8_t b = data[i + 2];

        uint16_t color = (r >> 3) << 11;
        color |= (g >> 2) << 5;
        color |= (b >> 3);

        oled_draw_pixel(x + (i / 2) % w, y + (i / 2) / w, color);
    }
