#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>
#include <math.h>

// Configuration
#define BH1750_ADDR 0x23
#define I2C_BUS 1
#define LED_GPIO 24
#define LOG_THRESHOLD 5.0
#define PWM_RANGE 255

// Global variables
int i2c_handle = -1;
FILE *log_file = NULL;
double last_logged_lux = -1.0;
int terminate = 0;

// Function prototypes
int init_gpio();
int init_i2c();
double read_light_level();
int adjust_led_brightness(double lux);
int log_light_level(double lux);
void signal_handler(int signal);
void cleanup();

int main() {
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO and I2C
    if (init_gpio() != 0) {
        fprintf(stderr, "Error initializing GPIO. Exiting.\n");
        return 1;
    }

    if (init_i2c() != 0) {
        fprintf(stderr, "Error initializing I2C. Exiting.\n");
        cleanup();
        return 1;
    }

    // Main loop
    while (!terminate) {
        double lux = read_light_level();
        if (lux >= 0) {
            adjust_led_brightness(lux);

            // Log light level if significant change
            if (last_logged_lux == -1.0 || fabs(lux - last_logged_lux) >= LOG_THRESHOLD) {
                if (log_light_level(lux) == 0) {
                    last_logged_lux = lux;
                } else {
                    fprintf(stderr, "Error logging light level.\n");
                }
            }
        } else {
            fprintf(stderr, "Error reading light level.\n");
        }

        gpioDelay(100); // Delay for 100ms
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

// Initialize GPIO
int init_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_GPIO, PI_OUTPUT);
    gpioPWM(LED_GPIO, 0); // Initialize PWM to 0
    gpioSetPWMrange(LED_GPIO, PWM_RANGE);
    gpioSetPWMfrequency(LED_GPIO, 1000); // Set PWM frequency to 1 kHz

    return 0;
}

// Initialize I2C
int init_i2c() {
    i2c_handle = i2cOpen(I2C_BUS, BH1750_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        return 1;
    }
    return 0;
}

// Read light level from BH1750 sensor
double read_light_level() {
    char config[1] = {0x10}; // Continuous high resolution mode
    if (i2cWriteByteData(i2c_handle, 0x00, config[0]) < 0) { // Use i2cWriteByteData to send configuration
        fprintf(stderr, "Error writing to I2C device\n");
        return -1.0;
    }
    gpioDelay(200); // Wait for measurement (at least 180ms)

    char buffer[2];
    int bytes_read = i2cReadDevice(i2c_handle, buffer, 2);
    if (bytes_read != 2) {
        fprintf(stderr, "Error reading from I2C device: %d\n", bytes_read);
        return -1.0;
    }

    unsigned int raw_value = (buffer[0] << 8) | buffer[1];
    return (double)raw_value / 1.2; // Convert to lux
}

// Adjust LED brightness based on lux value
int adjust_led_brightness(double lux) {
    // Map lux value to PWM duty cycle (0-255)
    int duty_cycle = (int)(lux / 1000.0 * PWM_RANGE); // Scale lux to 0-1000 range, then map to 0-255
    if (duty_cycle < 0) duty_cycle = 0;
    if (duty_cycle > PWM_RANGE) duty_cycle = PWM_RANGE;

    gpioPWM(LED_GPIO, duty_cycle);
    return 0;
}

// Log light level to file
int log_light_level(double lux) {
    if (log_file == NULL) {
        log_file = fopen("light_log.txt", "a");
        if (log_file == NULL) {
            fprintf(stderr, "Error opening log file\n");
            return 1;
        }
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    int result = fprintf(log_file, "%s: %.2f lux\n", timestamp, lux);
    if (result < 0) {
        fprintf(stderr, "Error writing to log file\n");
        fclose(log_file);
        log_file = NULL;
        return 1;
    }

    fflush(log_file); // Flush the buffer to ensure data is written
    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    fprintf(stderr, "Caught signal %d. Exiting gracefully.\n", signal);
    terminate = 1;
}

// Cleanup resources
void cleanup() {
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioPWM(LED_GPIO, 0); // Turn off LED
    gpioTerminate();
}

