    i2cClose(i2c_handle);
    gpioTerminate();
    fclose(log_file);
    printf("Program terminated gracefully.\n");
    return 0;
}

int initialize() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO mode for LED
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    // Open I2C bus
    i2c_handle = i2cOpen(I2C_BUS, BH1750_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C bus: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    return 0;
}

int read_bh1750(int i2c_handle) {
    unsigned char data[2];
    int reading;

    // Start measurement (high resolution mode)
    if (i2cWriteByte(i2c_handle, 0x10) != 0) {
        fprintf(stderr, "Failed to start measurement.\n");
        return -1;
    }
    gpioDelay(200); // Wait for measurement

    // Read two bytes of data
    if (i2cReadDevice(i2c_handle, (char *)data, 2) != 2) {
        fprintf(stderr, "Failed to read data from sensor.\n");
        return -1;
    }

    // Combine the bytes into a 16-bit value
    reading = (data[0] << 8) | data[1];

    return (float)reading / 1.2; // Convert to lux
}

int adjust_led_brightness(int current_brightness, float lux, int *new_brightness) {
    float target_brightness = (lux - MIN_LUX) / (MAX_LUX - MIN_LUX);

    // Smooth the target brightness using a simple moving average filter
    target_brightness = (1 - SMOOTHING_FACTOR) * current_brightness + SMOOTHING_FACTOR * target_brightness;

    // Ensure brightness is within the valid range
    if (target_brightness < 0) {
        target_brightness = 0;
    } else if (target_brightness > 255) {
        target_brightness = 255;
    }

    *new_brightness = (int)target_brightness;
    return *new_brightness;
}

void log_lux_reading(float lux, int brightness) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(log_file, "%s, %.2f, %d\n", timestamp, lux, brightness);
    fflush(log_file); // Ensure data is written to disk immediately

    // Log error if file operation fails
    if (ferror(log_file)) {
        log_error("Failed to write to log file.");
    }
}

void signal_handler(int signal) {
    printf("Signal received, exiting...\n");
    program_running = 0;
}

void log_error(const char *message) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    FILE *error_file = fopen(ERROR_LOG_FILE, "a");
    if (error_file != NULL) {
        fprintf(error_file, "%s, %s\n", timestamp, message);
        fclose(error_file);
    } else {
        fprintf(stderr, "Failed to open error log file.\n");
    }
}
