#include <signal.h>
#include <unistd.h>

#include <syslog.h>

#define SYSLOG_IDENTIFIER "hw4"

// Define a signal handler function
void signalHandler(int signum) {
    if (signum == SIGINT) {
        printf("Shutting down...\n");
        // Log an error message
        syslog(LOG_ERR, "Received SIGINT signal");
        // Shutdown wiringPi
        wiringPiShutdown();
        // Close syslog
        closelog();
        exit(0);
    }
}

int main(void) {
    // Define a signal handler
    signal(SIGINT, signalHandler);

    // Log an error message
    openlog(SYSLOG_IDENTIFIER, LOG_CONS | LOG_PERROR | LOG_PID | LOG_NDELAY, LOG_USER);
    syslog(LOG_ERR, "Starting up...");

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        syslog(LOG_ERR, "Could not initialize wiringPi");
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(0, 500000) == -1) {
        syslog(LOG_ERR, "Could not initialize SPI");
        return 1;
    }

    // Set GPIO 17 to be an input
    pinMode(17, INPUT);
    // Set GPIO 23 to be an output
    pinMode(23, OUTPUT);
    // Set GPIO 24 to be an output
    pinMode(24, OUTPUT);

    // Define an infinite loop
    while (1) {
        // Read the value on GPIO 17 and store it in val
        int val = digitalRead(17);
        // If val is 0
        if (val == 0) {
            // Turn on GPIO 23
            digitalWrite(23, HIGH);
            // Turn on GPIO 24
            digitalWrite(24, HIGH);
            // Wait 1 second
            delay(1000);
            // Turn off GPIO 23
            digitalWrite(23, LOW);
            // Turn off GPIO 24
            digitalWrite(24, LOW);
        }
    }

    return 0;
}
