#define SERVO_MAX_PULSE_WIDTH 2500

// Function to set the pan servo angle
void set_pan_angle(int angle) {
    // Map angle (0-180) to pulse width (500-2500)
    int pulse_width = (int)(((float)angle / 180.0) * (SERVO_MAX_PULSE_WIDTH - SERVO_MIN_PULSE_WIDTH) + SERVO_MIN_PULSE_WIDTH);
    gpioServo(PAN_SERVO_PIN, pulse_width);
}

// Function to set the tilt servo angle
void set_tilt_angle(int angle) {
    // Map angle (0-180) to pulse width (500-2500)
    int pulse_width = (int)(((float)angle / 180.0) * (SERVO_MAX_PULSE_WIDTH - SERVO_MIN_PULSE_WIDTH) + SERVO_MIN_PULSE_WIDTH);
    gpioServo(TILT_SERVO_PIN, pulse_width);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set servo pins as outputs
    gpioSetMode(PAN_SERVO_PIN, PI_OUTPUT);
    gpioSetMode(TILT_SERVO_PIN, PI_OUTPUT);

    // Main loop: synchronized panning and tilting
    while (1) {
        // Panning (angle increases with time)
        for (int angle = 0; angle <= 180; angle += 10) {
            set_pan_angle(angle);
            set_tilt_angle(angle); // Tilting the same angle
            usleep(50000); // Delay for smooth movement (50ms)
        }

        // Tilting (angle decreases with time)
        for (int angle = 180; angle >= 0; angle -= 10) {
            set_pan_angle(angle);
            set_tilt_angle(angle);
            usleep(50000); // Delay for smooth movement (50ms)
        }
    }

    // Terminate pigpio library (this will never be reached in the infinite loop)
    gpioTerminate();

    return 0;
}

