#define SPI_BUS 0
#define SPI_CS 1

// This is for the 74HC595
#define LATCH_PIN 24
#define CLOCK_PIN 23
#define DATA_PIN 25

#define RESET_DELAY 10

uint16_t display_numbers(uint8_t number)
{
    uint16_t val = 0;

    // We need to reset the 74HC595
    digitalWrite(LATCH_PIN, HIGH);
    usleep(RESET_DELAY);

    // Convert number to 8 bit binary
    val = number & 0xFF;

    // Write data to 74HC595
    digitalWrite(DATA_PIN, val & 0x01);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x02) >> 1);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x04) >> 2);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x08) >> 3);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x10) >> 4);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x20) >> 5);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x40) >> 6);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);
    digitalWrite(DATA_PIN, (val & 0x80) >> 7);
    digitalWrite(CLOCK_PIN, HIGH);
    usleep(1);
    digitalWrite(CLOCK_PIN, LOW);
    usleep(1);

    // Latch the 74HC595
    digitalWrite(LATCH_PIN, LOW);
    usleep(RESET_DELAY);
    digitalWrite(LATCH_PIN, HIGH);
    usleep(RESET_DELAY);

    return val;
}

int main(int argc, char **argv)
{
    if (wiringPiSetup() < 0)
        return 1;

    // Set up SPI
    wiringPiSPISetup(SPI_BUS, 500000);

    // Set up the 74HC595
    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(DATA_PIN, OUTPUT);

    // Set up the 7-segment display
    int fd = open("/dev/spidev0.0", O_RDWR);
    if (fd < 0)
    {
        printf("Failed to open SPI device\n");
        return 1;
    }

    struct spi_ioc_transfer tr = {
        .tx_buf = (unsigned long)NULL,
        .rx_buf = (unsigned long)NULL,
        .len = 0,
        .speed_hz = 1000000,
        .delay_usecs = 0,
        .bits_per_word = 8,
        .cs_change = 1,
        .tx_nbits = 0,
        .rx_nbits = 0,
        .pad = 0};

    // Set up the 7-segment display
    unsigned char out_data[] = {0x3F, 0x06, 0x5B, 0x4F, 0x66, 0x6D, 0x7D, 0x07, 0x7F, 0x6F, 0x77, 0x7C, 0x39, 0x5E, 0x79, 0x71, 0x85, 0x89};
    tr.tx_buf = (unsigned long)out_data;
    tr.len = 17;
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);

    // Set up the 74HC595
    unsigned char out_data2[] = {0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00};
    tr.tx_buf = (unsigned long)out_data2;
    tr.len = 17;
    ioctl(fd, SPI_IOC_MESSAGE(1), &tr);

    // Loop and display 9 on the display
    while (1)
    {
        printf("%d\n", display_numbers(9));
        sleep(1);
    }
    close(fd);
