#include <stdlib.h>
#include <pigpio.h>
#include <math.h>
#include <unistd.h>
#include <signal.h>
#include <errno.h>

// HMC5883L I2C address
#define HMC5883L_ADDR 0x1E

// HMC5883L register addresses
#define HMC5883L_CONFIG_A 0x00
#define HMC5883L_CONFIG_B 0x01
#define HMC5883L_MODE 0x02
#define HMC5883L_DATA_X_MSB 0x03
#define HMC5883L_DATA_X_LSB 0x04
#define HMC5883L_DATA_Z_MSB 0x05
#define HMC5883L_DATA_Z_LSB 0x06
#define HMC5883L_DATA_Y_MSB 0x07
#define HMC5883L_DATA_Y_LSB 0x08

// Gain setting (1 = +/- 1.3 Gauss)
#define HMC5883L_GAIN 0x20  //0x20 corresponds to gain = 1

// GPIO pin for LED
#define LED_PIN 18

int i2c_handle;
volatile sig_atomic_t terminate = 0;

void signal_handler(int sig) {
    terminate = 1;
    printf("Signal received, exiting gracefully...\n");
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(1, HMC5883L_ADDR, 0); // Bus 1, address 0x1E, no flags
    if (i2c_handle < 0) {
        perror("Error opening I2C connection");
        gpioTerminate();
        return 1;
    }

    // Configure HMC5883L for continuous measurement mode and gain setting
    if (i2cWriteByteData(i2c_handle, HMC5883L_CONFIG_A, 0x70) < 0) { // 8-average, 15 Hz, normal measurement
        perror("Error writing to CONFIG_A register");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    if (i2cWriteByteData(i2c_handle, HMC5883L_CONFIG_B, HMC5883L_GAIN) < 0) {
        perror("Error writing to CONFIG_B register");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    if (i2cWriteByteData(i2c_handle, HMC5883L_MODE, 0x00) < 0) { // Continuous measurement mode
        perror("Error writing to MODE register");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure LED pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Set up signal handling for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (!terminate) {
        // Read magnetometer data
        char buffer[6];
        if (i2cReadI2CBlockData(i2c_handle, HMC5883L_DATA_X_MSB, buffer, 6) != 6) {
            perror("Error reading magnetometer data");
            // Attempt to re-establish the I2C connection
            i2cClose(i2c_handle);
            i2c_handle = i2cOpen(1, HMC5883L_ADDR, 0);
            if (i2c_handle < 0) {
                fprintf(stderr, "Failed to re-establish I2C connection\n");
                terminate = 1; // Exit the loop if re-establishing fails
                continue;      // Skip the rest of the loop iteration
            }
            continue; // Skip to the next iteration if read failed
        }

        // Convert data to signed 16-bit integers (big-endian to little-endian)
        short x = (buffer[0] << 8) | buffer[1];
        short z = (buffer[2] << 8) | buffer[3];
        short y = (buffer[4] << 8) | buffer[5];

        // Calculate heading
        float heading = atan2(y, x);

        // Convert to degrees
        heading = heading * 180 / M_PI;

        // Adjust to 0-360 degree range
        if (heading < 0) {
            heading += 360;
        }

        printf("Heading: %.2f degrees\n", heading);

        // Map heading to PWM duty cycle (0-100%)
        int duty_cycle = (int)((heading / 360.0) * 1000000.0); //Full range PWM

        // Control LED brightness using PWM
        gpioPWM(LED_PIN, duty_cycle); //Use hardware PWM if available

        // Delay for a short period
        usleep(100000); // 100ms
    }

    // Cleanup
    gpioPWM(LED_PIN, 0); // Turn off LED
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

