void handle_i2c_error(int err)
{
    if (err == PI_BAD_SLAVE)
    {
        printf("I2C bus error: Bad slave.\n");
    }
    else if (err == PI_BAD_REGISTER)
    {
        printf("I2C bus error: Bad register.\n");
    }
    else if (err == PI_BAD_PARAMETER)
    {
        printf("I2C bus error: Bad parameter.\n");
    }
    else if (err == PI_BAD_FLAGS)
    {
        printf("I2C bus error: Bad flags.\n");
    }
    else if (err == PI_BAD_HANDLE)
    {
        printf("I2C bus error: Bad handle.\n");
    }
    else if (err == PI_BAD_POINTER)
    {
        printf("I2C bus error: Bad pointer.\n");
    }
    else if (err == PI_I2C_WRITE_FAILED)
    {
        printf("I2C bus error: I2C write failed.\n");
    }
    else if (err == PI_I2C_READ_FAILED)
    {
        printf("I2C bus error: I2C read failed.\n");
    }
    else if (err == PI_I2C_READ_FAILED)
    {
        printf("I2C bus error: I2C read failed.\n");
    }
    else if (err == PI_I2C_NO_DEVICES)
    {
        printf("I2C bus error: I2C no devices.\n");
    }
    else if (err == PI_I2C_NO_RETURN_PACKET)
    {
        printf("I2C bus error: I2C no return packet.\n");
    }
    else if (err == PI_I2C_READ_FAILED)
    {
        printf("I2C bus error: I2C read failed.\n");
    }
    else if (err == PI_I2C_TIMEOUT)
    {
        printf("I2C bus error: I2C timeout.\n");
    }
    else if (err == PI_I2C_NO_START)
    {
        printf("I2C bus error: I2C no start.\n");
    }
    else if (err == PI_I2C_NO_STOP)
    {
        printf("I2C bus error: I2C no stop.\n");
    }
    else if (err == PI_I2C_BUF_TOO_SMALL)
    {
        printf("I2C bus error: I2C buffer too small.\n");
    }
    else
    {
        printf("I2C bus error: Unknown error.\n");
    }
}

int main(int argc, char *argv[])
{
    int i2c_handle;
    char i2c_address = 0x1E;
    int i2c_reg_address = 0x00;
    char i2c_data[6];
    int i2c_bytes_read;
    int i2c_bytes_written;
    int i2c_data_size = 6;

    float heading;
    float x_axis_data;
    float y_axis_data;
    float z_axis_data;

    double x_axis;
    double y_axis;
    double z_axis;
    double total_axis;

    int gpio18_handle;
    int gpio18_pin = 18;
    int pwm_duty_cycle;

    gpioInitialise();

    // Open the I2C handle
    i2c_handle = i2cOpen(1, 400000);
    if (i2c_handle < 0)
    {
        printf("Failed to open I2C handle\n");
        return 0;
    }

    // Read the magnetometer data
    i2c_bytes_written = i2cWriteByteData(i2c_handle, i2c_address, i2c_reg_address, 0x00);
    if (i2c_bytes_written < 0)
    {
        printf("Failed to write to I2C bus\n");
        return 0;
    }

    i2c_bytes_read = i2cReadI2CBlockData(i2c_handle, i2c_address, i2c_data, i2c_data_size);
    if (i2c_bytes_read < 0)
    {
        printf("Failed to read from I2C bus\n");
        return 0;
    }

    // Calculate the heading
    x_axis_data = (i2c_data[1] << 8 | i2c_data[0]);
    x_axis_data = (x_axis_data / 32768.0) * 1000.0;
    y_axis_data = (i2c_data[3] << 8 | i2c_data[2]);
    y_axis_data = (y_axis_data / 32768.0) * 1000.0;
    z_axis_data = (i2c_data[5] << 8 | i2c_data[4]);
    z_axis_data = (z_axis_data / 32768.0) * 1000.0;
    total_axis = x_axis_data * x_axis_data + y_axis_data * y_axis_data + z_axis_data * z_axis_data;
    x_axis = x_axis_data / sqrt(total_axis);
    y_axis = y_axis_data / sqrt(total_axis);
    z_axis = z_axis_data / sqrt(total_axis);
    heading = atan2(y_axis, x_axis) * 180 / PI;

    // Calculate the PWM duty cycle based on the heading
    pwm_duty_cycle = (int) (100 * (heading / 360));
    printf("Heading: %f\tPWM Duty Cycle: %d\n", heading, pwm_duty_cycle);

    // Open the GPIO handle
    gpio18_handle = gpioInitialise();
    if (gpio18_handle < 0)
    {
        printf("Failed to open GPIO handle\n");
        return 0;
    }

    // Set the GPIO pin to output
    gpioSetMode(gpio18_handle, gpio18_pin, PI_OUTPUT);
    // Set the GPIO pin to the PWM duty cycle
    gpioPWM(gpio18_handle, gpio18_pin, pwm_duty_cycle);

    return 0;
}
