// HMC5883L register addresses
#define HMC5883L_CONFIG_A 0x00
#define HMC5883L_MODE 0x02
#define HMC5883L_DATA_X_MSB 0x03
#define HMC5883L_DATA_X_LSB 0x04
#define HMC5883L_DATA_Z_MSB 0x05
#define HMC5883L_DATA_Z_LSB 0x06
#define HMC5883L_DATA_Y_MSB 0x07
#define HMC5883L_DATA_Y_LSB 0x08

// GPIO pin for LED control
#define LED_GPIO 18

// I2C handle
int i2c_handle;

// Flag to indicate program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    terminate = 1;
    printf("Signal received, exiting gracefully...\n");
}

// Function to initialize the HMC5883L
int init_hmc5883l() {
    // Configure register 0x00 (Config A) - 8-average, 15 Hz, normal measurement
    if (i2cWriteByteData(i2c_handle, HMC5883L_CONFIG_A, 0x70) < 0) {
        fprintf(stderr, "Error writing to HMC5883L_CONFIG_A\n");
        return -1;
    }

    // Configure register 0x02 (Mode) - Continuous measurement mode
    if (i2cWriteByteData(i2c_handle, HMC5883L_MODE, 0x00) < 0) {
        fprintf(stderr, "Error writing to HMC5883L_MODE\n");
        return -1;
    }

    return 0;
}

// Function to read magnetometer data
int read_magnetometer_data(int16_t *x, int16_t *y, int16_t *z) {
    char buffer[6];

    if (i2cReadI2CBlockData(i2c_handle, HMC5883L_DATA_X_MSB, buffer, 6) != 6) {
        fprintf(stderr, "Error reading magnetometer data\n");
        return -1;
    }

    *x = (int16_t)((buffer[0] << 8) | buffer[1]);
    *z = (int16_t)((buffer[2] << 8) | buffer[3]);
    *y = (int16_t)((buffer[4] << 8) | buffer[5]);

    return 0;
}

// Function to calculate heading in degrees
float calculate_heading(int16_t x, int16_t y) {
    float heading = atan2((float)y, (float)x) * 180 / M_PI;
    if (heading < 0) {
        heading += 360;
    }
    return heading;
}

// Function to set LED brightness using PWM
void set_led_brightness(float heading) {
    int duty_cycle = (int)((heading / 360.0) * 100.0);
    if (duty_cycle < 0) duty_cycle = 0;
    if (duty_cycle > 100) duty_cycle = 100;

    gpioPWM(LED_GPIO, duty_cycle * 2.55); // pigpio duty cycle is 0-255
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, HMC5883L_ADDR, 0); // Bus 1, address 0x1E, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device\n");
        gpioTerminate();
        return 1;
    }

    // Initialize HMC5883L
    if (init_hmc5883l() < 0) {
        fprintf(stderr, "HMC5883L initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set LED GPIO as output
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    // Set up signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    int16_t x, y, z;
    float heading;

    // Main loop
    while (!terminate) {
        // Read magnetometer data
        if (read_magnetometer_data(&x, &y, &z) == 0) {
            // Calculate heading
            heading = calculate_heading(x, y);

            // Set LED brightness
            set_led_brightness(heading);
        } else {
            fprintf(stderr, "Error reading magnetometer data. Retrying...\n");
        }

        // Delay
        gpioDelay(100000); // 100ms
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioWrite(LED_GPIO, 0); // Turn off LED
    gpioTerminate();

    return 0;
}
```

