#include <unistd.h>

// GPIO Pin definitions
#define PIN_BUTTON 4
#define PIN_LOCK_0 17
#define PIN_LOCK_1 27

// Logging functions
void log_to_file(const char* lock_id, const char* action, const char* timestamp) {
    // Open file for writing
    FILE* file = fopen("lock_events.log", "a");

    // Write to file
    fprintf(file, "%s\t%s\t%s\n", timestamp, lock_id, action);

    // Close file
    fclose(file);
}

// Logging timestamp
char* log_timestamp() {
    // Get current time
    time_t rawtime;
    time (&rawtime);

    // Get formatted time
    char* time_string = ctime(&rawtime);

    // Trim newline character
    time_string[strlen(time_string) - 1] = '\0';

    // Return formatted time
    return time_string;
}

// Debouncing function
int debounce(int gpio_pin, int threshold) {
    int count = 0;
    int level = gpioRead(gpio_pin);
    while (count < threshold) {
        int l = gpioRead(gpio_pin);
        if (l != level) {
            level = l;
            count = 0;
        }
        count++;
        usleep(10000);
    }
    return level;
}

// GPIO initialization
void gpio_init(void) {
    // Open connection to pigpio
    int pi = pigpio_start("192.168.1.11", 8888, 0);

    // Set all GPIO pins as input
    gpioSetMode(PIN_BUTTON, PI_INPUT);
    gpioSetMode(PIN_LOCK_0, PI_INPUT);
    gpioSetMode(PIN_LOCK_1, PI_INPUT);

    // Set all GPIO pins as pull-up
    gpioSetPullUpDown(PIN_BUTTON, PI_PUD_UP);
    gpioSetPullUpDown(PIN_LOCK_0, PI_PUD_UP);
    gpioSetPullUpDown(PIN_LOCK_1, PI_PUD_UP);

    // Clean up
    pigpio_stop(pi);
}

// Main function
int main(void) {
    // Initialize GPIO pins
    gpio_init();

    // Initialize variables
    int button_level = 0;
    char* lock_id = "";
    char* action = "";
    char* timestamp = "";

    // Initialize buffer
    char buffer[32] = {0};

    // Initialize lock statuses
    int lock_0_status = 0;
    int lock_1_status = 0;

    // Main loop
    while (1) {
        // Get button level
        button_level = debounce(PIN_BUTTON, 10);

        // Get lock statuses
        lock_0_status = gpioRead(PIN_LOCK_0);
        lock_1_status = gpioRead(PIN_LOCK_1);

        // Reset buffer
        buffer[0] = '\0';

        // Get lock ID and action
        if (button_level == 0 && lock_0_status == 0) {
            lock_id = "0";
            action = "open";
        }
        else if (button_level == 0 && lock_0_status == 1) {
            lock_id = "0";
            action = "close";
        }
        else if (button_level == 0 && lock_1_status == 0) {
            lock_id = "1";
            action = "open";
        }
        else if (button_level == 0 && lock_1_status == 1) {
            lock_id = "1";
            action = "close";
        }

        // Write to buffer
        strcat(buffer, lock_id);
        strcat(buffer, "_");
        strcat(buffer, action);

        // Get timestamp
        timestamp = log_timestamp();

        // Log to file
        log_to_file(buffer, timestamp, timestamp);
    }

    return 0;
}
