        gpioDelay(100); // Reduce CPU usage
    }

    // Clean up
    printf("Cleaning up...\n");
    gpioWrite(LOCK_1_GPIO, 0); // Lock both locks on exit
    gpioWrite(LOCK_2_GPIO, 0);
    fclose(log_file);
    gpioTerminate();

    printf("Exiting.\n");
    return 0;
}
