                int led_index = rand() % NUM_LEDS;
                int selected_led = led_gpios[led_index];

                printf("Fading LED on GPIO %d\n", selected_led);

                // Fade the selected LED
                fade_led(selected_led);

                // Small delay to prevent rapid triggering
                gpioDelay(200000); // 200ms

                break; // Exit the sensor loop after detecting a touch
            }
        }
