    if (delay_ms == 0) delay_ms = 1; // Avoid division by zero

    for (int duty_cycle = start_duty_cycle; duty_cycle <= end_duty_cycle; duty_cycle++) {
        set_led_pwm(gpio, duty_cycle);
        gpioDelay(delay_ms);
    }
    set_led_pwm(gpio, end_duty_cycle); // Ensure final state is correct
}

