/*
 * This program monitors the air quality using an MQ-135 sensor connected to GPIO 4 and activates a 12V ventilation fan connected to GPIO 17 via a relay when
 * the CO2 concentration exceeds a threshold of 200 ppm. It logs the timestamps and sensor readings to air_quality.log, with error handling for pigpio
 * initialization failures.
 */

int main() {
  int i = 0;
  int count = 0;
  float avg = 0;
  float avg_2 = 0;
  float avg_3 = 0;
  float avg_4 = 0;
  float avg_5 = 0;
  int threshold = 200;
  int sensor = 4;
  int fan = 17;
  int relay = 22;
  int pigpio_return = 0;

  // initialize pigpio
  if (pigpio_return = pigpio_start(NULL, NULL)) {
    fprintf(stderr, "pigpio failed to start\n");
    return -1;
  }

  // open GPIO 4 for analog input
  if (pigpio_return = pigpio_open(sensor, PI_INPUT)) {
    fprintf(stderr, "failed to open GPIO 4\n");
    return -1;
  }

  // open GPIO 17 for analog output
  if (pigpio_return = pigpio_open(fan, PI_OUTPUT)) {
    fprintf(stderr, "failed to open GPIO 17\n");
    return -1;
  }

  // open GPIO 22 for relay
  if (pigpio_return = pigpio_open(relay, PI_OUTPUT)) {
    fprintf(stderr, "failed to open GPIO 22\n");
    return -1;
  }

  // set GPIO 17 low
  if (pigpio_return = pigpio_write(fan, 0)) {
    fprintf(stderr, "failed to set GPIO 17 low\n");
    return -1;
  }

  // set GPIO 22 low
  if (pigpio_return = pigpio_write(relay, 0)) {
    fprintf(stderr, "failed to set GPIO 22 low\n");
    return -1;
  }

  // initialize log file
  FILE *log = fopen("air_quality.log", "w");

  while (1) {
    // wait 1 second
    sleep(1);

    // read from GPIO 4
    if (pigpio_return = pigpio_read(sensor)) {
      fprintf(stderr, "failed to read from GPIO 4\n");
      return -1;
    }

    // average the last 5 readings
    avg = (avg_4 + avg_3 + avg_2 + avg_1 + pigpio_return) / 5;

    if (avg > threshold) {
      // set GPIO 17 high
      if (pigpio_return = pigpio_write(fan, 1)) {
        fprintf(stderr, "failed to set GPIO 17 high\n");
        return -1;
      }

      // set GPIO 22 high
      if (pigpio_return = pigpio_write(relay, 1)) {
        fprintf(stderr, "failed to set GPIO 22 high\n");
        return -1;
      }

      // log the current time and the current average
      fprintf(log, "%ld %f\n", time(NULL), avg);

      // log a warning if the average is greater than the threshold
      if (count == 0) {
        printf("WARNING: Air quality is above %d ppm.\n", threshold);
        count++;
      }
    } else {
      // set GPIO 17 low
      if (pigpio_return = pigpio_write(fan, 0)) {
        fprintf(stderr, "failed to set GPIO 17 low\n");
        return -1;
      }

      // set GPIO 22 low
      if (pigpio_return = pigpio_write(relay, 0)) {
        fprintf(stderr, "failed to set GPIO 22 low\n");
        return -1;
      }

      // log the current time and the current average
      fprintf(log, "%ld %f\n", time(NULL), avg);

      // reset count
      count = 0;
    }

    // shift the average
    avg_5 = avg_4;
    avg_4 = avg_3;
    avg_3 = avg_2;
    avg_2 = avg_1;
    avg_1 = pigpio_return;

    // reset count
    count = 0;
  }

  return 0;
}
