#define PIR_PIN 17
#define BUZZER_PIN 27
#define DELAY_MS 250

void open_log() {
    int log_fd = openlog("pi-pir-buzzer", LOG_PID, LOG_USER);

    if (log_fd < 0) {
        syslog(LOG_ERR, "failed to open syslog");
        exit(EXIT_FAILURE);
    }
}

void close_log() {
    int ret = closelog();
    if (ret < 0) {
        syslog(LOG_ERR, "failed to close syslog");
    }
}

void log_message(int priority, char *message) {
    syslog(priority, "%s", message);
}

int init_gpio() {
    int ret = gpioInitialise();
    if (ret < 0) {
        log_message(LOG_ERR, "failed to initialize gpio");
        return -1;
    }
    return ret;
}

void setup_pir() {
    int pir_pin = gpioInitialise();

    if (pir_pin < 0) {
        log_message(LOG_ERR, "failed to initialize gpio");
        exit(EXIT_FAILURE);
    }

    int ret = gpioSetMode(PIR_PIN, PI_INPUT);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to set GPIO mode");
        exit(EXIT_FAILURE);
    }

    ret = gpioSetPullUpDown(PIR_PIN, PI_PUD_UP);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to set GPIO pull up");
        exit(EXIT_FAILURE);
    }
}

void setup_buzzer() {
    int ret = gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to set GPIO mode");
        exit(EXIT_FAILURE);
    }
}

void turn_on_buzzer() {
    int ret = gpioWrite(BUZZER_PIN, PI_HIGH);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to turn on buzzer");
        exit(EXIT_FAILURE);
    }
}

void turn_off_buzzer() {
    int ret = gpioWrite(BUZZER_PIN, PI_LOW);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to turn off buzzer");
        exit(EXIT_FAILURE);
    }
}

void trigger_buzzer() {
    int ret = gpioWrite(BUZZER_PIN, PI_LOW);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to turn on buzzer");
        exit(EXIT_FAILURE);
    }

    usleep(DELAY_MS * 1000);

    ret = gpioWrite(BUZZER_PIN, PI_HIGH);
    if (ret < 0) {
        log_message(LOG_ERR, "failed to turn off buzzer");
        exit(EXIT_FAILURE);
    }
}

void wait_for_pir() {
    int pir_val = gpioRead(PIR_PIN);

    while (pir_val == 0) {
        usleep(DELAY_MS * 1000);
        pir_val = gpioRead(PIR_PIN);
    }
}

int main() {
    open_log();

    int ret = init_gpio();
    if (ret < 0) {
        syslog(LOG_ERR, "failed to initialize gpio");
        return EXIT_FAILURE;
    }

    setup_pir();
    setup_buzzer();

    while (1) {
        wait_for_pir();
        log_message(LOG_INFO, "motion detected");
        turn_on_buzzer();
        trigger_buzzer();
        turn_off_buzzer();
    }

    close_log();
    return EXIT_SUCCESS;
}
