#define PIR_PIN_1 17
#define PIR_PIN_2 18
#define BUZZER_PIN 27

// Buzzer duration in milliseconds
#define BUZZER_DURATION 500

// Function prototypes
int read_sensor(int gpio_pin);
void trigger_buzzer(int duration_ms);
void signal_handler(int signal);

// Global variable for pigpio initialization status
int pigpio_initialized = 0;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    syslog(LOG_INFO, "Signal received, shutting down...");

    // Disable buzzer
    gpioWrite(BUZZER_PIN, 0);

    // Terminate pigpio
    if (pigpio_initialized) {
        gpioTerminate();
        pigpio_initialized = 0;
        syslog(LOG_INFO, "pigpio terminated.");
    }

    closelog();
    exit(0);
}

// Function to read the sensor value from a given GPIO pin
int read_sensor(int gpio_pin) {
    return gpioRead(gpio_pin);
}

// Function to trigger the buzzer for a specified duration
void trigger_buzzer(int duration_ms) {
    gpioWrite(BUZZER_PIN, 1); // Turn on buzzer
    gpioDelay(duration_ms * 1000); // Delay in microseconds
    gpioWrite(BUZZER_PIN, 0); // Turn off buzzer
}

int main() {
    // Open syslog
    openlog("smart_agriculture", LOG_PID | LOG_CONS, LOG_USER);

    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        syslog(LOG_ERR, "pigpio initialisation failed");
        closelog();
        return 1;
    }
    pigpio_initialized = 1;
    syslog(LOG_INFO, "pigpio initialised successfully.");

    // Set GPIO modes
    gpioSetMode(PIR_PIN_1, PI_INPUT);
    gpioSetMode(PIR_PIN_2, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);

    // Ensure buzzer is initially off
    gpioWrite(BUZZER_PIN, 0);

    syslog(LOG_INFO, "Smart Agriculture System started.");

    // Main loop
    while (1) {
        // Read sensor values
        int sensor1_value = read_sensor(PIR_PIN_1);
        int sensor2_value = read_sensor(PIR_PIN_2);

        // Check for motion detection
        if (sensor1_value == 1) {
            syslog(LOG_INFO, "Motion detected by sensor 1 (GPIO %d).", PIR_PIN_1);
            trigger_buzzer(BUZZER_DURATION);
        }
        if (sensor2_value == 1) {
            syslog(LOG_INFO, "Motion detected by sensor 2 (GPIO %d).", PIR_PIN_2);
            trigger_buzzer(BUZZER_DURATION);
        }

        // Delay to avoid excessive CPU usage
        gpioDelay(100000); // 100 milliseconds
    }

    return 0;
}
