#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins
#define SENSOR_1_PIN 4
#define SENSOR_2_PIN 22
#define BUZZER_1_PIN 18
#define BUZZER_2_PIN 23
#define STOP_BUTTON_PIN 17

// Debouncing delay in milliseconds
#define DEBOUNCE_DELAY 50

// Structure to hold sensor and buzzer data
typedef struct {
    int sensor_pin;
    int buzzer_pin;
} SensorBuzzerPair;

// Function prototypes
int initialize_gpio();
void sensor_isr(int gpio, int level, uint32_t tick, void *user_data);
void stop_button_isr(int gpio, int level, uint32_t tick, void *user_data);
void start_buzzer(int buzzer_pin);
void stop_buzzer(int buzzer_pin);

// Global flag for debouncing (volatile because it's modified in an ISR)
volatile int button_pressed = 0;

int main() {
    // Initialize pigpio
    if (initialize_gpio() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Sensor 1 data
    SensorBuzzerPair sensor1_data = {SENSOR_1_PIN, BUZZER_1_PIN};

    // Sensor 2 data
    SensorBuzzerPair sensor2_data = {SENSOR_2_PIN, BUZZER_2_PIN};

    // Set interrupt routines for sensors
    gpioSetISRFuncEx(SENSOR_1_PIN, RISING_EDGE, 0, sensor_isr, &sensor1_data);
    gpioSetISRFuncEx(SENSOR_2_PIN, RISING_EDGE, 0, sensor_isr, &sensor2_data);

    // Set interrupt routine for stop button
    gpioSetISRFuncEx(STOP_BUTTON_PIN, FALLING_EDGE, 0, stop_button_isr, NULL); // No user data needed for stop button

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Keep the program running
    while (1) {
        sleep(1); // Reduce CPU usage
    }

    // Terminate pigpio before exiting
    gpioTerminate();
    return 0;
}

// Initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        return -1;
    }

    // Set sensor pins as inputs with pull-down resistors
    gpioSetMode(SENSOR_1_PIN, PI_INPUT);
    gpioSetPullUpDown(SENSOR_1_PIN, PI_PUD_DOWN);

    gpioSetMode(SENSOR_2_PIN, PI_INPUT);
    gpioSetPullUpDown(SENSOR_2_PIN, PI_PUD_DOWN);

    // Set buzzer pins as outputs
    gpioSetMode(BUZZER_1_PIN, PI_OUTPUT);
    gpioSetMode(BUZZER_2_PIN, PI_OUTPUT);

    // Set stop button pin as input with pull-up resistor
    gpioSetMode(STOP_BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(STOP_BUTTON_PIN, PI_PUD_UP);

    return 0;
}

// Interrupt service routine for sensors
void sensor_isr(int gpio, int level, uint32_t tick, void *user_data) {
    SensorBuzzerPair *data = (SensorBuzzerPair *)user_data;

    if (level == 1) { // Rising edge (motion detected)
        printf("Motion detected on sensor at GPIO %d\n", gpio);
        start_buzzer(data->buzzer_pin);
    }
}

// Interrupt service routine for stop button
void stop_button_isr(int gpio, int level, uint32_t tick, void *user_data) {
    if (level == 0 && !button_pressed) { // Falling edge (button pressed) and not debouncing
        button_pressed = 1; // Set the flag to indicate the button has been pressed
        printf("Stop button pressed. Stopping all buzzers.\n");
        stop_buzzer(BUZZER_1_PIN);
        stop_buzzer(BUZZER_2_PIN);

        // Debounce delay
        gpioDelay(DEBOUNCE_DELAY * 1000); // Delay in microseconds
        button_pressed = 0; // Reset the flag after the delay
    }
}

// Start the buzzer
void start_buzzer(int buzzer_pin) {
    gpioWrite(buzzer_pin, 1); // Set the pin HIGH to activate the buzzer
    printf("Buzzer at GPIO %d started\n", buzzer_pin);
}

// Stop the buzzer
void stop_buzzer(int buzzer_pin) {
    gpioWrite(buzzer_pin, 0); // Set the pin LOW to deactivate the buzzer
    printf("Buzzer at GPIO %d stopped\n", buzzer_pin);
}

