{
  static int buzzer_on = 0;
  static int debounce_ms = 0;
  static int buzzer_timeout_ms = 0;

  if (level)
  {
    if (buzzer_on)
    {
      debounce_ms = BUZZER_TIMEOUT_MS;
    }
    else
    {
      debounce_ms = 0;
      buzzer_timeout_ms = BUZZER_TIMEOUT_MS;
      buzzer_on = 1;
    }
  }
  else
  {
    if (debounce_ms > 0)
    {
      debounce_ms -= BUZZER_PERIOD_MS;
    }
    else if (buzzer_timeout_ms > 0)
    {
      buzzer_timeout_ms -= BUZZER_PERIOD_MS;
    }
    else
    {
      buzzer_on = 0;
    }
  }

  if (buzzer_on)
  {
    pigpio_gpioWrite(BUZZER_PIN, 1);
  }
  else
  {
    pigpio_gpioWrite(BUZZER_PIN, 0);
  }
}

