#include <unistd.h>
#include <string.h>

#define PIR_GPIO_PIN 17
#define PIR_GPIO_SPI_CHANNEL 0
#define PIR_GPIO_SPI_SPEED 1000000

int main(){

	// Set up wiringPi
	if(wiringPiSetup() < 0){
		printf("Error setting up wiringPi. 1\n");
		return 1;
	}

	// Set up SPI
	if(wiringPiSPISetup(PIR_GPIO_SPI_CHANNEL, PIR_GPIO_SPI_SPEED) < 0){
		printf("Error setting up SPI. 2\n");
		return 2;
	}

	// Set up GPIO pin
	if(wiringPiSetupGpio() < 0){
		printf("Error setting up GPIO. 3\n");
		return 3;
	}

	// Open file
	FILE* file = fopen("motion_log.txt", "a");
	if(file == NULL){
		printf("Error opening file. 4\n");
		return 4;
	}

	// Loop
	int i = 0;
	while(1){
		// Get SPI data
		unsigned char data[2];
		if(wiringPiSPIDataRW(PIR_GPIO_SPI_CHANNEL, data, 2) < 0){
			printf("Error reading SPI data. 5\n");
			return 5;
		}

		// Check if motion detected
		if(data[1] & 0x01){
			// Get timestamp
			char buffer[100];
			time_t rawtime;
			struct tm * timeinfo;
			time ( &rawtime );
			timeinfo = localtime ( &rawtime );
			strftime (buffer,100,"%d-%m-%Y %I:%M:%S",timeinfo);
			fprintf(file, "%s\n", buffer);
			fflush(file);
		}

		// Sleep
		sleep(1);

		// Increase counter
		i++;
	}
}
