#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>

#define LED_GPIO 27
#define PIR_GPIO 17
#define BUF_SIZE 256

void set_led(int on) {
    gpioWrite(LED_GPIO, on);
}

void set_pir(int on) {
    gpioWrite(PIR_GPIO, on);
}

int get_pir_state(void) {
    return gpioRead(PIR_GPIO);
}

void log_event(int state, char* event_type) {
    time_t now;
    struct tm* tm_info;
    char buffer[BUF_SIZE];
    char* time_string;

    time(&now);
    tm_info = localtime(&now);
    time_string = asctime(tm_info);

    if (state) {
        snprintf(buffer, BUF_SIZE, "%s %s\n", event_type, time_string);
        printf("%s", buffer);
        fflush(stdout);
        fprintf(stderr, "%s", buffer);
        fflush(stderr);
    } else {
        snprintf(buffer, BUF_SIZE, "%s %s\n", event_type, time_string);
        printf("%s", buffer);
        fflush(stdout);
        fprintf(stderr, "%s", buffer);
        fflush(stderr);
    }
    fflush(stdout);
    fflush(stderr);
}

int main() {
    int ret;

    printf("Starting pigpio_pir_door_lock_test\n");

    ret = gpioInitialise();
    if (ret < 0) {
        fprintf(stderr, "gpioInitialise failed\n");
        return -1;
    }

    gpioSetMode(LED_GPIO, PI_OUTPUT);
    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetPullUpDown(PIR_GPIO, PI_PUD_UP);

    while (1) {
        int pir_state = get_pir_state();
        if (pir_state) {
            set_led(0);
            log_event(pir_state, "PIR on");
        } else {
            set_led(1);
            log_event(pir_state, "PIR off");
        }
        usleep(100000);
    }

    gpioTerminate();
    printf("Ending pigpio_pir_door_lock_test\n");
    return 0;
}
