#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>

// Define GPIO pins
#define PIR_PIN 17
#define RELAY_PIN 27

// Global variables for signal handling
volatile sig_atomic_t program_running = 1;

// Function prototypes
int read_sensor(int gpio_pin);
int control_relay(int gpio_pin, int state);
int log_event(const char *event_type);
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("\nCaught SIGINT, exiting gracefully.\n");
        program_running = 0;
        control_relay(RELAY_PIN, 0); // Ensure relay is off on exit
        gpioTerminate(); // Terminate pigpio
        exit(0);
    }
}

// Function to read sensor value
int read_sensor(int gpio_pin) {
    return gpioRead(gpio_pin);
}

// Function to control relay state
int control_relay(int gpio_pin, int state) {
    if (gpioWrite(gpio_pin, state) != 0) {
        fprintf(stderr, "Error: Failed to write to GPIO %d\n", gpio_pin);
        return -1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to log events to file
int log_event(const char *event_type) {
    FILE *fp = fopen("door_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error: Failed to open log file.\n");
        return -1; // Indicate failure
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s - %s\n", s, event_type);
    fclose(fp);
    return 0; // Indicate success
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        int motion_detected = read_sensor(PIR_PIN);

        if (motion_detected) {
            printf("Motion detected!\n");
            if (control_relay(RELAY_PIN, 1) == 0) { // Turn relay ON
                log_event("Door Unlocked");
                gpioDelay(5000); // Keep relay ON for 5 seconds
                control_relay(RELAY_PIN, 0); // Turn relay OFF
                log_event("Door Locked");
            } else {
                fprintf(stderr, "Error: Failed to control relay.\n");
            }
        }

        gpioDelay(100); // Check every 100ms
    }

    // Cleanup (should not reach here if signal handler is used)
    control_relay(RELAY_PIN, 0); // Ensure relay is off on exit
    gpioTerminate(); // Terminate pigpio

    return 0;
}
