#include <stdlib.h>
#include <pigpio.h>
#include <time.h>

// Define GPIO pins
#define MOTION_SENSOR_PIN 17
#define RELAY_PIN 27

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioSetMode(MOTION_SENSOR_PIN, PI_INPUT) != 0) {
        fprintf(stderr, "Error setting GPIO%d to input.\n", MOTION_SENSOR_PIN);
        return 1; // Indicate failure
    }
    if (gpioSetMode(RELAY_PIN, PI_OUTPUT) != 0) {
        fprintf(stderr, "Error setting GPIO%d to output.\n", RELAY_PIN);
        return 1; // Indicate failure
    }
    return 0; // Indicate success
}

// Function to read the motion sensor
int read_motion_sensor() {
    return gpioRead(MOTION_SENSOR_PIN);
}

// Function to activate the relay for 5 seconds
void activate_relay() {
    gpioWrite(RELAY_PIN, 1); // Turn relay ON
    gpioDelay(5000000);      // Wait for 5 seconds (5000000 microseconds)
    gpioWrite(RELAY_PIN, 0); // Turn relay OFF
}

// Function to log the motion event with a timestamp
void log_motion_event() {
    FILE *fp;
    time_t rawtime;
    struct tm *timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    fp = fopen("motion_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening motion_log.txt for writing.\n");
        return;
    }

    fprintf(fp, "Motion detected at: %s", asctime(timeinfo));
    fclose(fp);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed\n");
        gpioTerminate();
        return 1;
    }

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    while (1) {
        if (read_motion_sensor() == 1) {
            printf("Motion detected!\n");
            activate_relay();
            log_motion_event();
            gpioDelay(1000000); // Debounce: wait 1 second before checking again
        } else {
            gpioDelay(100000); // Check every 0.1 seconds if no motion
        }
    }

    gpioTerminate();
    return 0;
}

