    fp = fopen("motion_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening motion_log.txt for writing!\n");
        return;
    }

    fprintf(fp, "%s: Motion detected and relay activated.\n", timestamp);
    fclose(fp);
}

