    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed!\n");
        return 1; // Exit with an error code
    }

    // Configure GPIO17 as input
    gpioSetMode(PIR_PIN, PI_INPUT);

    // Configure GPIO27 as output
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Main loop
