#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>

// Define GPIO pins
#define PIR_SENSOR_1 17
#define PIR_SENSOR_2 22
#define BUZZER 18

// Function prototypes
int initialize_gpio();
int read_sensor(int gpio_pin);
void activate_buzzer(int duration_ms);
void cleanup_gpio();
void signal_handler(int signal);

// Global variable to track program state for signal handling
volatile sig_atomic_t program_running = 1;

int main() {
    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        // Read sensor values
        int sensor1_value = read_sensor(PIR_SENSOR_1);
        int sensor2_value = read_sensor(PIR_SENSOR_2);

        // Check if motion is detected by either sensor
        if (sensor1_value == 1 || sensor2_value == 1) {
            printf("Motion detected! Activating buzzer.\n");
            activate_buzzer(2000); // Activate buzzer for 2 seconds
        }

        gpioDelay(100); // Delay for 100ms to avoid excessive CPU usage
    }

    // Cleanup GPIO before exiting
    cleanup_gpio();

    printf("Program terminated gracefully.\n");
    return 0;
}

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set PIR sensor pins as input
    gpioSetMode(PIR_SENSOR_1, PI_INPUT);
    gpioSetMode(PIR_SENSOR_2, PI_INPUT);

    // Set buzzer pin as output
    gpioSetMode(BUZZER, PI_OUTPUT);

    return 0;
}

// Function to read sensor value
int read_sensor(int gpio_pin) {
    return gpioRead(gpio_pin);
}

// Function to activate the buzzer
void activate_buzzer(int duration_ms) {
    gpioWrite(BUZZER, 1); // Turn buzzer on
    gpioDelay(duration_ms); // Delay for specified duration
    gpioWrite(BUZZER, 0); // Turn buzzer off
}

// Function to cleanup GPIO pins
void cleanup_gpio() {
    gpioTerminate();
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    program_running = 0;
    printf("Received signal %d. Exiting...\n", signal);
}
