/*
 * Name: HC-SR501 PIR Motion Sensor
 * Description:
 *   - Use the pigpio library to detect motion via a HC-SR501 PIR sensor
 *     (GPIO 17) and trigger a piezo buzzer (GPIO 18) with interrupt-driven
 *     routines; implement debouncing and log event timestamps to 'motion.log'
 *     in ISO 8601 format, handling potential pigpio initialization errors
 *     gracefully.
 */

#include <pigpio.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <string.h>

// Define constants
#define PIR_PIN 17
#define BUZZER_PIN 18

// Define global variables
int motion_status = 0;
int motion_count = 0;
int motion_debounce_delay = 1000000;

// Define function prototypes
void motion_debounce(int);
void motion_log(char *, int);
int motion_detect(int);

// Define function implementations
void motion_debounce(int state)
{
    motion_status = state;

    if (motion_status == 0)
    {
        motion_count = 0;
    }
    else
    {
        motion_count++;
    }

    return;
}

void motion_log(char *msg, int state)
{
    if (state == 0)
    {
        printf("%s\n", msg);
    }
    else
    {
        time_t now = time(NULL);
        struct tm *t = localtime(&now);
        char str[100];
        strftime(str, 100, "%FT%T", t);
        printf("%s - %s\n", msg, str);
    }

    return;
}

int motion_detect(int state)
{
    if (state == 0)
    {
        motion_log("PIR motion sensor is off", 0);
    }
    else
    {
        motion_log("PIR motion sensor is on", 1);
    }

    return 0;
}

int main(int argc, char **argv)
{
    // Set the state to off
    motion_log("PIR motion sensor is off", 0);

    // Initialize pigpio library
    int init_state = gpioInitialise();
    if (init_state < 0)
    {
        printf("Pigpio initialization failed\n");
        return 1;
    }

    // Setup pins for GPIO 17
    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetPullUpDown(PIR_PIN, PI_PUD_UP);

    // Setup pins for GPIO 18
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetPullUpDown(BUZZER_PIN, PI_PUD_UP);

    // Register interrupts for GPIO 17
    gpioSetAlertFunc(PIR_PIN, motion_debounce);
    gpioSetPullUpDown(PIR_PIN, PI_PUD_UP);
    gpioSetAlertFunc(PIR_PIN, motion_detect);

    // Infinite loop
    while (1)
    {
        if (motion_status != motion_count)
        {
            if (motion_status == 0)
            {
                motion_log("PIR motion sensor is off", 0);
            }
            else
            {
                motion_log("PIR motion sensor is on", 1);
            }

            motion_status = motion_count;
        }

        gpioSleep(motion_debounce_delay);
    }

    // End program
    return 0;
}
