        return 1;
    }

    // Open log file
    log_file = fopen("motion.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open motion.log\n");
        return 1;
    }

    // Register interrupt handler for rising edge detection
    interrupt_data_t data = {PIR_SENSOR_PIN};
    if (gpioSetISRFuncEx(PIR_SENSOR_PIN, RISING_EDGE, DEBOUNCE_TIME, motion_detected_callback, &data) != 0) {
        fprintf(stderr, "Failed to set ISR function\n");
        return 1;
    }

    return 0;
}

// Function to cleanup GPIO pins and close log file
void cleanup_gpio(void) {
    // Disable buzzer
    gpioWrite(BUZZER_PIN, 0);

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Terminate pigpio
    gpioTerminate();
}

// Interrupt handler function
